// SYSTÈME COINS — recharge + kiffements
// ─────────────────────────────────────────────
const RECHARGES = [
  { coins:10, prix:100 },
  { coins:50, prix:500 },
  { coins:100, prix:1000 },
  { coins:500, prix:5000 },
];

const KIFFEMENTS = [
  { id:'note', label:'Note', coins:1, partArtiste:70 },
  { id:'micro', label:'Micro', coins:5, partArtiste:350 },
  { id:'trophee', label:'Trophée', coins:10, partArtiste:700 },
  { id:'couronne', label:'Couronne', coins:50, partArtiste:3500 },
];

function KiffementSection({ qrId, artistEmail }: { qrId: string, artistEmail?: string }) {
  const [open, setOpen] = useState(false);
  const [showRecharge, setShowRecharge] = useState(false);
  const [soldeCoins, setSoldeCoins] = useState(0);
  const [sending, setSending] = useState<string|null>(null);
  const [msg, setMsg] = useState('');
  const [showLoginModal, setShowLoginModal] = useState('');
  const user = auth.currentUser;

  // Charger le solde coins de l'utilisateur
  useEffect(() => {
    if (!user) return;
    const unsub = onSnapshot(
      query(collection(db,'coins_solde'), where('uid','==',user.uid)),
      snap => {
        if (!snap.empty) setSoldeCoins(snap.docs[0].data().solde || 0);
        else setSoldeCoins(0);
      }
    );
    return unsub;
  }, [user]);

  const envoyer = async (kiffement: typeof KIFFEMENTS[0]) => {
    if (!user) { setShowLoginModal('Connectez-vous pour envoyer un kiffement'); return; }
    if (soldeCoins < kiffement.coins) {
      setShowRecharge(true);
      return;
    }
    setSending(kiffement.id);
    try {
      // Débiter les coins
      const snap = await getDocs(query(collection(db,'coins_solde'), where('uid','==',user.uid)));
      if (!snap.empty) {
        await updateDoc(doc(db,'coins_solde',snap.docs[0].id), { solde: soldeCoins - kiffement.coins });
      }
      // Enregistrer le kiffement
      await addDoc(collection(db,'cadeaux'), {
        qrId, artistEmail,
        kiffementId: kiffement.id,
        kiffementLabel: kiffement.label,
        coins: kiffement.coins,
        partArtiste: kiffement.partArtiste,
        userId: user.uid,
        userName: user.displayName || user.email?.split('@')[0],
        status: 'paid',
        createdAt: new Date().toISOString(),
      });
      // Notification artiste
      if (artistEmail) {
        await addDoc(collection(db,'notifications'), {
          to: artistEmail,
          type: 'kiffement',
          text: `${user.displayName || 'Un fan'} vous a envoyé ${kiffement.coins} coins — ${kiffement.label}`,
          qrId, from: user.displayName || user.email,
          createdAt: new Date().toISOString(),
          lu: false,
        });
      }
      setMsg(`Kiffement envoyé ! ${kiffement.coins} coins débités.`);
      setTimeout(() => setMsg(''), 3000);
    } catch(e) { console.error(e); }
    setSending(null);
  };

  return (
    <div style={{ marginBottom:16 }}>
      {showLoginModal && <LoginModal message={showLoginModal} onClose={() => setShowLoginModal('')} />}
      <button onClick={() => setOpen(!open)}
        style={{ display:'flex', alignItems:'center', gap:6, padding:'8px 16px', borderRadius:99, border:'1px solid rgba(255,200,0,0.3)', background:'rgba(255,200,0,0.05)', color:'#ffd700', cursor:'pointer', fontSize:14, fontWeight:600 }}>
        Kiffement
      </button>

      {open && (
        <div style={{ marginTop:12, background:'rgba(255,255,255,0.03)', border:'1px solid rgba(255,200,0,0.15)', borderRadius:14, padding:14 }}>

          {/* Solde coins */}
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:12 }}>
            <p style={{ color:'#8098b8', fontSize:12, margin:0 }}>Votre solde</p>
            <div style={{ display:'flex', alignItems:'center', gap:8 }}>
              <span style={{ color:'#ffd700', fontWeight:800, fontSize:14 }}>{soldeCoins} coins</span>
              <button onClick={() => setShowRecharge(!showRecharge)}
                style={{ padding:'4px 10px', borderRadius:8, border:'1px solid rgba(255,215,0,0.4)', background:'rgba(255,215,0,0.1)', color:'#ffd700', fontSize:11, fontWeight:700, cursor:'pointer' }}>
                Recharger
              </button>
            </div>
          </div>

          {/* Panel recharge */}
          {showRecharge && (
            <div style={{ background:'rgba(0,0,0,0.3)', borderRadius:10, padding:12, marginBottom:12 }}>
              <p style={{ color:'#ffd700', fontSize:12, fontWeight:700, marginBottom:8 }}>Recharger mes coins</p>
              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:8, marginBottom:8 }}>
                {RECHARGES.map(r => (
                  <button key={r.coins} onClick={() => {
                    // En attendant API — afficher le numéro de paiement
                    alert(`Envoyez ${r.prix} FCFA sur Wave au +225 05 02 10 14 52\nObjet : "${r.coins} coins - ${user?.email}"\nVos coins seront crédités sous 24h.`);
                  }}
                    style={{ padding:'10px 6px', borderRadius:10, border:'1px solid rgba(255,215,0,0.2)', background:'rgba(255,215,0,0.06)', cursor:'pointer', textAlign:'center' }}>
                    <p style={{ color:'#ffd700', fontWeight:800, fontSize:15, margin:'0 0 2px' }}>{r.coins} coins</p>
                    <p style={{ color:'#8098b8', fontSize:11, margin:0 }}>{r.prix.toLocaleString()} FCFA</p>
                  </button>
                ))}
              </div>
              <p style={{ color:'#4a5878', fontSize:10, textAlign:'center', margin:0 }}>Paiement via Wave · Orange Money · MTN MoMo</p>
            </div>
          )}

          {msg && <p style={{ color:'#ffd700', fontSize:12, marginBottom:8 }}>{msg}</p>}

          {/* Kiffements */}
          <p style={{ color:'#8098b8', fontSize:11, marginBottom:8 }}>Choisissez un kiffement</p>
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:8 }}>
            {KIFFEMENTS.map(k => {
              const canSend = soldeCoins >= k.coins;
              return (
                <button key={k.id} onClick={() => envoyer(k)} disabled={sending === k.id}
                  style={{ padding:'12px 8px', borderRadius:12, border:`1px solid ${canSend?'rgba(255,200,0,0.3)':'rgba(255,255,255,0.05)'}`, background: canSend?'rgba(255,200,0,0.08)':'rgba(255,255,255,0.02)', cursor: canSend?'pointer':'not-allowed', textAlign:'center', opacity: canSend?1:0.5, transition:'all .2s' }}>
                  <p style={{ color: canSend?'#dde4f5':'#4a5878', fontSize:13, fontWeight:700, margin:'0 0 2px' }}>{k.label}</p>
                  <p style={{ color:'#ffd700', fontSize:11, margin:0 }}>{k.coins} coins</p>
                </button>
              );
            })}
          </div>
          <p style={{ color:'#4a5878', fontSize:10, marginTop:10, textAlign:'center' }}>70% reversé à l'artiste</p>
        </div>
      )}
    </div>
  );
}

// ─────────────────────────────────────────────
// SECTION COMMENTAIRES — style TikTok
// ─────────────────────────────────────────────
function CommentSection({ qrId, artistEmail }: { qrId: string, artistEmail?: string }) {
  const [comments, setComments] = useState<any[]>([]);
  const [count, setCount] = useState(0);
  const [text, setText] = useState('');
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [showLoginModal, setShowLoginModal] = useState('');
  const user = auth.currentUser;

  // Charger le compteur dès le montage
  useEffect(() => {
    if (!qrId) return;
    const unsub = onSnapshot(
      query(collection(db, 'commentaires'), where('qrId','==',qrId)),
      snap => setCount(snap.size)
    );
    return unsub;
  }, [qrId]);

  // Charger les commentaires complets quand ouvert
  useEffect(() => {
    if (!open || !qrId) return;
    const unsub = onSnapshot(
      query(collection(db, 'commentaires'), where('qrId','==',qrId), orderBy('createdAt','desc')),
      snap => setComments(snap.docs.map(d => ({id:d.id,...d.data()})))
    );
    return unsub;
  }, [qrId, open]);

  const submit = async () => {
    if (!user) { setShowLoginModal('Connectez-vous pour commenter'); return; }
    if (!text.trim()) return;
    setLoading(true);
    try {
      await addDoc(collection(db, 'commentaires'), {
        qrId, text: text.trim(),
        userId: user.uid,
        userName: user.displayName || user.email?.split('@')[0] || 'Anonyme',
        userPhoto: user.photoURL || '',
        createdAt: new Date().toISOString(),
      });
      // Notification à l'artiste
      if (artistEmail) {
        await addDoc(collection(db, 'notifications'), {
          to: artistEmail,
          type: 'commentaire',
          text: `Nouveau commentaire sur votre contenu`,
          qrId,
          from: user.displayName || user.email,
          createdAt: new Date().toISOString(),
          lu: false,
        });
      }
      setText('');
    } catch(e) { console.error(e); }
    setLoading(false);
  };

  return (
    <div style={{ marginBottom:16 }}>
      {showLoginModal && <LoginModal message={showLoginModal} onClose={() => setShowLoginModal('')} />}
      <button onClick={() => setOpen(!open)}
        style={{ display:'flex', alignItems:'center', gap:6, padding:'8px 16px', borderRadius:99, border:'1px solid rgba(255,255,255,0.1)', background:'transparent', color:'#8098b8', cursor:'pointer', fontSize:14, fontWeight:600 }}>
        Commenter {count > 0 ? count : ''}
      </button>

      {open && (
        <div style={{ marginTop:12, background:'rgba(255,255,255,0.03)', border:'1px solid rgba(255,255,255,0.06)', borderRadius:14, padding:14 }}>
          {/* Saisie commentaire */}
          <div style={{ display:'flex', gap:8, marginBottom:14 }}>
            <input value={text} onChange={e => setText(e.target.value)}
              onKeyDown={e => e.key==='Enter' && submit()}
              placeholder="Écrivez un commentaire..."
              style={{ flex:1, background:'rgba(255,255,255,0.06)', border:'1px solid rgba(255,255,255,0.1)', borderRadius:99, padding:'8px 14px', color:'#fff', fontSize:13, outline:'none' }} />
            <button onClick={submit} disabled={loading || !text.trim()}
              style={{ padding:'8px 14px', borderRadius:99, border:'none', background:'#1a6bff', color:'#fff', fontWeight:700, fontSize:13, cursor:'pointer' }}>
              {loading ? '...' : 'Envoyer'}
            </button>
          </div>
          {/* Liste commentaires */}
          {comments.length === 0 ? (
            <p style={{ color:'#4a5878', fontSize:12, textAlign:'center' }}>Soyez le premier à commenter</p>
          ) : comments.map(c => (
            <div key={c.id} style={{ display:'flex', gap:10, marginBottom:12 }}>
              <div style={{ width:32, height:32, borderRadius:99, background:'linear-gradient(135deg,#1a6bff,#4f46e5)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:14, flexShrink:0 }}>
                {c.userPhoto ? <img src={c.userPhoto} style={{ width:32, height:32, borderRadius:99 }} alt="" /> : c.userName?.[0]?.toUpperCase()}
              </div>
              <div style={{ flex:1 }}>
                <p style={{ fontWeight:700, fontSize:12, color:'#4da6ff', marginBottom:2 }}>{c.userName}</p>
                <p style={{ fontSize:13, color:'#dde4f5', lineHeight:1.5 }}>{c.text}</p>
                <p style={{ fontSize:10, color:'#4a5878', marginTop:2 }}>{new Date(c.createdAt).toLocaleDateString('fr')}</p>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// ─────────────────────────────────────────────
// TRAVAILLEURS — classement des donateurs + messages honorifiques
// ─────────────────────────────────────────────
const MESSAGES_HONORIFIQUES = [
  "Merci infiniment pour ton soutien, tu es un vrai Travailleur !",
  "Ton kiffement me touche profondément, que Dieu te bénisse !",
  "Tu es la raison pour laquelle je continue à créer. Merci !",
  "Un grand merci à toi, mon fidèle Travailleur !",
  "Ton soutien me donne de l'énergie. Je te dédie cette musique !",
];

function Travailleurs({ qrId, artistEmail }: { qrId: string, artistEmail?: string }) {
  const [travailleurs, setTravailleurs] = useState<any[]>([]);
  const [showReply, setShowReply] = useState<string|null>(null);
  const [replyMsg, setReplyMsg] = useState('');
  const user = auth.currentUser;
  const isArtist = user?.email === artistEmail;

  useEffect(() => {
    const unsub = onSnapshot(
      query(collection(db,'cadeaux'), where('qrId','==',qrId)),
      snap => {
        const map: Record<string, any> = {};
        snap.docs.forEach(d => {
          const data = d.data();
          const uid = data.userId;
          if (!map[uid]) map[uid] = { userId:uid, userName:data.userName, coins:0, count:0 };
          map[uid].coins += data.coins || 0;
          map[uid].count += 1;
        });
        const sorted = Object.values(map).sort((a:any,b:any) => b.coins - a.coins);
        setTravailleurs(sorted);
      }
    );
    return unsub;
  }, [qrId]);

  const getTitre = (coins: number) => {
    if (coins >= 50) return { titre:'Travailleur Elite', color:'#ffd700' };
    if (coins >= 20) return { titre:'Grand Travailleur', color:'#c0c0c0' };
    if (coins >= 10) return { titre:'Travailleur', color:'#cd7f32' };
    return { titre:'Supporter', color:'#8098b8' };
  };

  const sendReply = async (travailleur: any) => {
    if (!replyMsg) return;
    await addDoc(collection(db,'notifications'), {
      to: travailleur.userId,
      type: 'remerciement',
      text: replyMsg,
      from: user?.displayName || artistEmail,
      qrId,
      createdAt: new Date().toISOString(),
      lu: false,
    });
    setShowReply(null);
    setReplyMsg('');
    alert('Message envoyé !');
  };

  if (travailleurs.length === 0) return null;

  return (
    <div style={{ marginBottom:16 }}>
      <p style={{ fontSize:11, fontWeight:700, color:'#ffd700', letterSpacing:1, marginBottom:8, textTransform:'uppercase' }}>
        Travailleurs
      </p>
      {travailleurs.slice(0,5).map((t,i) => {
        const { titre, color } = getTitre(t.coins);
        return (
          <div key={t.userId} style={{ display:'flex', alignItems:'center', gap:10, padding:'8px 12px', background:'rgba(255,215,0,0.06)', border:'1px solid rgba(255,215,0,0.15)', borderRadius:10, marginBottom:6 }}>
            <span style={{ fontSize:16, fontWeight:900, color:'#ffd700', minWidth:20 }}>#{i+1}</span>
            <div style={{ flex:1 }}>
              <p style={{ fontWeight:700, fontSize:13, color:'#dde4f5', margin:0 }}>{t.userName}</p>
              <p style={{ fontSize:10, color, margin:0 }}>{titre} · {t.coins} coins · {t.count} kiffements</p>
            </div>
            {isArtist && (
              <button onClick={() => setShowReply(showReply === t.userId ? null : t.userId)}
                style={{ padding:'4px 10px', borderRadius:8, border:'1px solid rgba(255,215,0,0.3)', background:'transparent', color:'#ffd700', fontSize:11, cursor:'pointer' }}>
                Remercier
              </button>
            )}
          </div>
        );
      })}

      {/* Panel remerciement */}
      {showReply && isArtist && (
        <div style={{ background:'rgba(255,215,0,0.06)', border:'1px solid rgba(255,215,0,0.2)', borderRadius:12, padding:14, marginTop:8 }}>
          <p style={{ color:'#ffd700', fontSize:12, fontWeight:700, marginBottom:8 }}>Message honorifique</p>
          <div style={{ display:'flex', flexDirection:'column', gap:6, marginBottom:10 }}>
            {MESSAGES_HONORIFIQUES.map((m,i) => (
              <button key={i} onClick={() => setReplyMsg(m)}
                style={{ padding:'8px 12px', borderRadius:8, border:`1px solid ${replyMsg===m?'#ffd700':'rgba(255,215,0,0.2)'}`, background: replyMsg===m?'rgba(255,215,0,0.1)':'transparent', color:'#dde4f5', fontSize:12, cursor:'pointer', textAlign:'left' }}>
                {m}
              </button>
            ))}
          </div>
          <div style={{ display:'flex', gap:8 }}>
            <button onClick={() => sendReply(travailleurs.find(t => t.userId === showReply))}
              style={{ flex:1, padding:10, borderRadius:10, border:'none', background:'#ffd700', color:'#1a2340', fontWeight:700, fontSize:13, cursor:'pointer' }}>
              Envoyer
            </button>
            <button onClick={() => setShowReply(null)}
              style={{ padding:10, borderRadius:10, border:'1px solid rgba(255,255,255,0.1)', background:'transparent', color:'#8098b8', fontSize:13, cursor:'pointer' }}>
              Annuler
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

// ─────────────────────────────────────────────
// TUTO POINTER — flèche qui pointe le vrai bouton
// ─────────────────────────────────────────────
const TUTO_STEPS = [
  { id:'btn-play', label:'Écoutez', desc:'Appuyez sur Play pour écouter la musique de votre artiste', color:'#1a6bff' },
  { id:'btn-download', label:'Téléchargez', desc:'Téléchargez ce contenu sur votre téléphone', color:'#1a6bff' },
  { id:'btn-like', label:'Kiffez', desc:'Appuyez sur Kiff pour soutenir votre artiste', color:'#f04a6a' },
  { id:'btn-kiffement', label:'Kiffement', desc:'Envoyez un kiffement — 70% va directement à l\'artiste', color:'#ffd700' },
  { id:'btn-ziko', label:'Zikothèque', desc:'Ajoutez à votre Zikothèque pour retrouver ce contenu partout', color:'#7c3aed' },
  { id:'pwa-install-btn', label:'Installer l\'app', desc:'Installez Doniel Zik pour accéder à votre musique partout', color:'#1a6bff' },
];

function TutoPointer({ step, onNext, onSkip }: { step: number, onNext: () => void, onSkip: () => void }) {
  const [arrowPos, setArrowPos] = useState<{x:number,y:number,w:number,h:number}|null>(null);
  const current = TUTO_STEPS[step - 1];
  const retryRef = useRef<any>(null);

  const findAndPosition = () => {
    if (!current?.id) { setArrowPos(null); return; }
    const el = document.getElementById(current.id);
    if (!el) {
      retryRef.current = setTimeout(findAndPosition, 300);
      return;
    }
    const rect = el.getBoundingClientRect();
    setArrowPos({ x: rect.left + rect.width/2, y: rect.top, w: Math.max(rect.width, 40), h: Math.max(rect.height, 40) });
  };

  useEffect(() => {
    if (retryRef.current) clearTimeout(retryRef.current);
    setArrowPos(null);
    // Attendre 500ms que le DOM se stabilise
    retryRef.current = setTimeout(findAndPosition, 500);
    return () => { if (retryRef.current) clearTimeout(retryRef.current); };
  }, [step]); // eslint-disable-line react-hooks/exhaustive-deps

  const isLast = step === 6;

  return (
    <div style={{ position:'fixed', inset:0, zIndex:9998, pointerEvents:'none' }}>
      <style>{`
        @keyframes tutoArrow { 0%,100%{transform:translateY(0) translateX(-50%)} 50%{transform:translateY(-10px) translateX(-50%)} }
        @keyframes tutoSlide { from{opacity:0;transform:translateY(24px)} to{opacity:1;transform:translateY(0)} }
        @keyframes tutoPulse { 0%,100%{transform:scale(1);opacity:0.8} 50%{transform:scale(1.2);opacity:0.4} }
      `}</style>

      {/* Overlay sombre */}
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.6)' }} />

      {/* Flèche + cercle sur le bouton */}
      {arrowPos && (
        <>
          {/* Cercle pulsant autour du bouton */}
          <div style={{
            position:'absolute',
            left: arrowPos.x - arrowPos.w/2 - 8,
            top: arrowPos.y - 8,
            width: arrowPos.w + 16,
            height: arrowPos.h + 16,
            borderRadius: 99,
            border: `3px solid ${current.color}`,
            boxShadow: `0 0 0 4px ${current.color}33`,
            animation: 'tutoPulse 1.2s ease infinite',
            zIndex: 9999,
          }} />
          {/* Flèche pointante */}
          <div style={{
            position:'absolute',
            left: arrowPos.x,
            top: arrowPos.y - 50,
            animation: 'tutoArrow 0.8s ease infinite',
            zIndex: 9999,
          }}>
            <svg width="28" height="36" viewBox="0 0 28 36">
              <polygon points="14,36 0,0 28,0" fill={current.color}/>
            </svg>
          </div>
        </>
      )}

      {/* Bulle info en bas */}
      <div style={{ position:'absolute', bottom:0, left:0, right:0, pointerEvents:'auto', animation:'tutoSlide .3s ease' }}>
        <div style={{ background:'#fff', borderRadius:'20px 20px 0 0', padding:'20px 24px 36px', maxWidth:500, margin:'0 auto', boxShadow:'0 -8px 32px rgba(0,0,0,0.3)' }}>
          {/* Points de progression */}
          <div style={{ display:'flex', justifyContent:'center', gap:6, marginBottom:16 }}>
            {TUTO_STEPS.map((_,i) => (
              <div key={i} style={{ width:i+1===step?24:8, height:8, borderRadius:99, background:i+1===step?current.color:'#dce6f7', transition:'all .3s' }} />
            ))}
          </div>

          <p style={{ fontWeight:800, fontSize:17, color:'#1a2340', textAlign:'center', marginBottom:8 }}>{current.label}</p>
          <p style={{ color:'#5a7090', fontSize:13, lineHeight:1.7, textAlign:'center', marginBottom:20 }}>{current.desc}</p>

          {isLast ? (
            <>
              <button onClick={() => { document.getElementById('pwa-install-btn')?.click(); onSkip(); }}
                style={{ width:'100%', padding:14, borderRadius:12, border:'none', background:'linear-gradient(135deg,#1a6bff,#0050d0)', color:'#fff', fontWeight:800, fontSize:15, cursor:'pointer', marginBottom:10 }}>
                Installer Doniel Zik
              </button>
              <button onClick={onSkip}
                style={{ width:'100%', padding:10, borderRadius:12, border:'1px solid #dce6f7', background:'transparent', color:'#8098b8', fontSize:13, cursor:'pointer' }}>
                Plus tard
              </button>
            </>
          ) : (
            <div style={{ display:'flex', gap:10 }}>
              <button onClick={onSkip}
                style={{ flex:1, padding:10, borderRadius:12, border:'1px solid #dce6f7', background:'transparent', color:'#b0c4d8', fontSize:13, cursor:'pointer' }}>
                Passer
              </button>
              <button onClick={onNext}
                style={{ flex:2, padding:12, borderRadius:12, border:'none', background:current.color, color:'#fff', fontWeight:700, fontSize:14, cursor:'pointer' }}>
                Suivant →
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// ACTION BAR — barre horizontale Kiff · Commenter · Kiffement · Buzz
// ─────────────────────────────────────────────
function ActionBar({ qrId, artistEmail, buzz, tutoStep, onTutoNext }: {
  qrId: string, artistEmail?: string, buzz: number, tutoStep: number, onTutoNext: () => void
}) {
  const [kiffs, setKiffs] = useState(0);
  const [kiffed, setKiffed] = useState(false);
  const [showComments, setShowComments] = useState(false);
  const [showKiffements, setShowKiffements] = useState(false);
  const [totalCoins, setTotalCoins] = useState(0);
  const [commentCount, setCommentCount] = useState(0);
  const [showLoginModal, setShowLoginModal] = useState('');
  const user = auth.currentUser;

  useEffect(() => {
    const unsub1 = onSnapshot(query(collection(db,'likes'),where('qrId','==',qrId)), snap => {
      setKiffs(snap.size);
      if (user) setKiffed(snap.docs.some(d => d.data().userId === user.uid));
    });
    const unsub2 = onSnapshot(query(collection(db,'commentaires'),where('qrId','==',qrId)), snap => setCommentCount(snap.size));
    const unsub3 = onSnapshot(query(collection(db,'cadeaux'),where('qrId','==',qrId)), snap => {
      const coins = snap.docs.reduce((s,d) => s + (d.data().coins||0), 0);
      setTotalCoins(coins);
    });
    return () => { unsub1(); unsub2(); unsub3(); };
  }, [qrId, user]);

  const toggleKiff = async () => {
    if (!user) { setShowLoginModal('Connectez-vous pour kiffer votre artiste'); return; }
    if (kiffed) {
      const snap = await getDocs(query(collection(db,'likes'),where('qrId','==',qrId),where('userId','==',user.uid)));
      for (const d of snap.docs) await deleteDoc(doc(db,'likes',d.id));
    } else {
      await addDoc(collection(db,'likes'),{ qrId, userId:user.uid, createdAt:new Date().toISOString() });
    }
    if (tutoStep === 3) onTutoNext();
  };

  const btnStyle = (active?: boolean, color?: string) => ({
    flex:1,
    display:'flex',
    flexDirection:'column' as const,
    alignItems:'center',
    gap:3,
    padding:'10px 4px',
    border:'none',
    background: active ? `rgba(${color||'30,111,255'},0.12)` : 'rgba(255,255,255,0.04)',
    borderRadius:12,
    cursor:'pointer',
    color: active ? (color ? `rgb(${color})` : '#1a6bff') : '#8098b8',
    transition:'all .2s',
  });

  return (
    <div style={{ marginBottom:16 }}>
      {showLoginModal && <LoginModal message={showLoginModal} onClose={() => setShowLoginModal('')} />}
      {/* Barre principale */}
      <div id="action-bar" style={{ display:'flex', gap:6, marginBottom:8 }}>
        {/* KIFF */}
        <button id="btn-like" onClick={toggleKiff} style={btnStyle(kiffed, '240,74,106')}>
          <svg width="20" height="20" viewBox="0 0 24 24" fill={kiffed?'#f04a6a':'none'} stroke={kiffed?'#f04a6a':'#8098b8'} strokeWidth="2">
            <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/>
          </svg>
          <span style={{ fontSize:10, fontWeight:700 }}>Kiff {kiffs > 0 ? kiffs : ''}</span>
        </button>

        {/* COMMENTER */}
        <button id="btn-comment" onClick={() => { setShowComments(!showComments); if (tutoStep === 4) onTutoNext(); }} style={btnStyle(showComments)}>
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>
          </svg>
          <span style={{ fontSize:10, fontWeight:700 }}>Commenter {commentCount > 0 ? commentCount : ''}</span>
        </button>

        {/* KIFFEMENT */}
        <button id="btn-kiffement" onClick={() => { setShowKiffements(!showKiffements); if (tutoStep === 5) onTutoNext(); }} style={btnStyle(showKiffements, '255,215,0')}>
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/>
          </svg>
          <span style={{ fontSize:10, fontWeight:700 }}>Kiffement {totalCoins > 0 ? totalCoins+'c' : ''}</span>
        </button>

        {/* BUZZ */}
        <div style={{ ...btnStyle(), cursor:'default' }}>
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/>
          </svg>
          <span style={{ fontSize:10, fontWeight:700 }}>Buzz {buzz > 0 ? buzz : ''}</span>
        </div>
      </div>

      {/* Section commentaires dépliable */}
      {showComments && <CommentSection qrId={qrId} artistEmail={artistEmail} />}

      {/* Section kiffements dépliable */}
      {showKiffements && <KiffementSection qrId={qrId} artistEmail={artistEmail} />}
    </div>
  );
}

// ─────────────────────────────────────────────
// LIKE BUTTON — like sur un contenu
// ─────────────────────────────────────────────
function LikeButton({ qrId }: { qrId: string }) {
  const [liked, setLiked] = useState(false);
  const [count, setCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const user = auth.currentUser;

  useEffect(() => {
    if (!qrId) return;
    // Charger le nombre de likes
    const unsub = onSnapshot(
      query(collection(db, 'likes'), where('qrId','==', qrId)),
      snap => {
        setCount(snap.size);
        if (user) setLiked(snap.docs.some(d => d.data().userId === user.uid));
      }
    );
    return unsub;
  }, [qrId, user]);

  const toggle = async () => {
    if (!user) { alert('Connectez-vous pour liker ce contenu'); return; }
    if (loading) return;
    setLoading(true);
    try {
      if (liked) {
        const snap = await getDocs(query(collection(db, 'likes'), where('qrId','==',qrId), where('userId','==',user.uid)));
        for (const d of snap.docs) await deleteDoc(doc(db,'likes',d.id));
      } else {
        await addDoc(collection(db, 'likes'), { qrId, userId: user.uid, createdAt: new Date().toISOString() });
      }
    } catch(e) { console.error(e); }
    setLoading(false);
  };

  return (
    <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom:16 }}>
      <button onClick={toggle}
        style={{ display:'flex', alignItems:'center', gap:6, padding:'8px 16px', borderRadius:99, border:`1px solid ${liked?'rgba(240,74,106,0.5)':'rgba(255,255,255,0.1)'}`, background: liked?'rgba(240,74,106,0.1)':'transparent', color: liked?'#f04a6a':'#8098b8', cursor:'pointer', fontSize:14, fontWeight:600, transition:'all .2s' }}>
        Kiff {count > 0 ? count.toLocaleString() : ''}
      </button>
    </div>
  );
}

// ─────────────────────────────────────────────
// AUDIO PLAYER — bannière pub pendant lecture + timer 7s + VideoPlayer avec pub YouTube
// ─────────────────────────────────────────────
function AudioPlayer({ files, onStream, onPlay }: { files: any[], onStream?: (track: string, duration: number) => void, onPlay?: () => void }) {
  const [idx, setIdx] = useState(0);
  const [playing, setPlaying] = useState(false);
  const [progress, setProgress] = useState(0);
  const [dur, setDur] = useState(0);
  const [ct, setCt] = useState(0);
  const ref = useRef<HTMLAudioElement>(null);
  const streamStart = useRef<number>(0);
  const stopTimer = useRef<any>(null);
  const cur = files[idx];

  // Pub plein écran après arrêt/fin
  const [showPubAfter, setShowPubAfter] = useState(false);
  const [pendingNext, setPendingNext] = useState(false);

  // Pub pendant lecture audio — 3 fois par piste, sans son, passable après 5s
  const [showPubDuringPlay, setShowPubDuringPlay] = useState(false);
  const pubIntervalRef = useRef<any>(null);
  const pubCountRef = useRef(0);

  useEffect(() => {
    pubCountRef.current = 0; // reset à chaque nouvelle piste
    if (pubIntervalRef.current) clearInterval(pubIntervalRef.current);
    if (playing) {
      // Pub après 20s, 40s, 60s (3 fois max par piste)
      pubIntervalRef.current = setInterval(() => {
        if (playing && pubCountRef.current < 3) {
          pubCountRef.current++;
          setShowPubDuringPlay(true);
        } else {
          clearInterval(pubIntervalRef.current);
        }
      }, 20000);
    }
    return () => { if (pubIntervalRef.current) clearInterval(pubIntervalRef.current); };
  }, [playing, idx]); // eslint-disable-line react-hooks/exhaustive-deps

  const toggle = () => {
    if (!ref.current) return;
    if (playing) {
      const elapsed = Date.now() / 1000 - streamStart.current;
      if (elapsed > 2 && onStream) onStream(cur?.name || 'Piste ' + (idx + 1), elapsed);
      ref.current.pause();
      setPlaying(false);
      // Timer 7s — si pas de reprise → pub plein écran
      stopTimer.current = setTimeout(() => {
        setPendingNext(false);
        setShowPubAfter(true);
      }, 7000);
    } else {
      if (stopTimer.current) clearTimeout(stopTimer.current);
      streamStart.current = Date.now() / 1000;
      ref.current.play().catch(() => setPlaying(false));
      setPlaying(true);
      // Déclencher tuto cascade au premier play
      if (onPlay) onPlay();
    }
  };

  useEffect(() => () => { if (stopTimer.current) clearTimeout(stopTimer.current); }, []);

  const prev = () => {
    if (idx > 0) { setIdx(i => i - 1); setPlaying(true); streamStart.current = Date.now() / 1000; }
  };

  const next = () => {
    if (idx < files.length - 1) { setIdx(i => i + 1); setPlaying(true); streamStart.current = Date.now() / 1000; }
  };

  const afterPub = () => {
    setShowPubAfter(false);
    if (pendingNext && idx < files.length - 1) {
      setIdx(i => i + 1);
      setPlaying(true);
      streamStart.current = Date.now() / 1000;
    }
    setPendingNext(false);
  };

  if (!files || files.length === 0) return null;

  return (
    <div style={{ background: 'rgba(15,20,40,0.95)', borderRadius: 20, padding: '20px 16px', border: '1px solid rgba(30,111,255,0.18)', boxShadow: '0 8px 32px rgba(0,0,0,0.5)' }}>

      {/* PUB plein écran après arrêt/fin */}
      {showPubAfter && <PubOverlay trigger="track" onDone={afterPub} />}

      {/* PUB plein écran pendant lecture — musique continue en arrière-plan */}
      {showPubDuringPlay && (
        <PubOverlay trigger="audio_during" silent={true} onDone={() => setShowPubDuringPlay(false)} />
      )}

      <audio ref={ref} src={cur?.url}
        onTimeUpdate={() => { if (ref.current) { setCt(ref.current.currentTime); setProgress((ref.current.currentTime / ref.current.duration) * 100 || 0); } }}
        onLoadedMetadata={() => { if (ref.current) setDur(ref.current.duration); }}
        onEnded={() => {
          if (onStream) onStream(cur?.name || 'Piste ' + (idx + 1), ref.current?.duration || 0);
          if (idx < files.length - 1) {
            setPlaying(false);
            setPendingNext(true);
            setShowPubAfter(true);
          } else { setPlaying(false); }
        }}
        preload="metadata" />

      {/* SPECTROGRAMME CSS PUR */}
      <div style={{ marginBottom: 14 }}>
        <Spectrogram playing={playing} />
      </div>

      {/* TITRE */}
      <div style={{ textAlign: 'center', marginBottom: 14 }}>
        <p style={{ fontWeight: 700, fontSize: 14, color: '#e8f0ff', marginBottom: 3, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', padding: '0 8px' }}>
          {cur?.name?.replace(/\.[^/.]+$/, '') || 'Piste ' + (idx + 1)}
        </p>
        <p style={{ color: 'rgba(100,140,220,0.5)', fontSize: 11 }}>{idx + 1} / {files.length}</p>
      </div>

      {/* BARRE DE PROGRESSION */}
      <div
        onClick={(e) => { if (!ref.current || !ref.current.duration) return; const r = e.currentTarget.getBoundingClientRect(); ref.current.currentTime = ((e.clientX - r.left) / r.width) * ref.current.duration; }}
        style={{ height: 4, background: 'rgba(255,255,255,0.08)', borderRadius: 99, marginBottom: 6, cursor: 'pointer' }}>
        <div style={{ height: '100%', width: progress + '%', background: 'linear-gradient(90deg, #1e6fff, #4da6ff)', borderRadius: 99, transition: 'width .1s', boxShadow: '0 0 8px rgba(30,111,255,0.5)' }} />
      </div>
      <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 10, color: 'rgba(100,140,220,0.45)', marginBottom: 18 }}>
        <span>{formatTime(ct)}</span><span>{formatTime(dur)}</span>
      </div>

      {/* CONTRÔLES */}
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', gap: 28 }}>
        <button onClick={prev} disabled={idx === 0}
          style={{ background: 'none', border: 'none', color: idx === 0 ? 'rgba(100,140,220,0.18)' : 'rgba(100,140,220,0.6)', fontSize: 22, cursor: idx === 0 ? 'default' : 'pointer', padding: 4 }}>⏮</button>
        <button id="btn-play" onClick={toggle}
          style={{ width: 58, height: 58, borderRadius: 99, border: 'none', background: 'linear-gradient(135deg, #1e6fff, #0050d0)', color: '#fff', fontSize: 24, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 4px 24px rgba(30,111,255,0.55)', flexShrink: 0 }}>
          {playing ? '⏸' : '▶'}
        </button>
        <button onClick={next} disabled={idx === files.length - 1}
          style={{ background: 'none', border: 'none', color: idx === files.length - 1 ? 'rgba(100,140,220,0.18)' : 'rgba(100,140,220,0.6)', fontSize: 22, cursor: idx === files.length - 1 ? 'default' : 'pointer', padding: 4 }}>⏭</button>
      </div>

      {/* LISTE PISTES */}
      {files.length > 1 && (
        <div style={{ marginTop: 16, borderTop: '1px solid rgba(30,111,255,0.1)', paddingTop: 12 }}>
          {files.map((f, i) => (
            <div key={i} onClick={() => { setIdx(i); setPlaying(true); streamStart.current = Date.now() / 1000; }}
              style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '9px 10px', borderRadius: 10, cursor: 'pointer', background: i === idx ? 'rgba(30,111,255,0.15)' : 'transparent', marginBottom: 2, transition: 'background 0.2s' }}>
              <span style={{ color: i === idx ? '#4da6ff' : 'rgba(100,140,220,0.35)', fontSize: 12, fontWeight: 700, minWidth: 20, textAlign: 'center' }}>
                {i === idx && playing ? '▶' : (i + 1)}
              </span>
              <span style={{ fontSize: 12, color: i === idx ? '#e8f0ff' : 'rgba(180,200,240,0.55)', flex: 1, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                {f.name?.replace(/\.[^/.]+$/, '') || 'Piste ' + (i + 1)}
              </span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
// ─────────────────────────────────────────────
// TUTO CASCADE — bulles qui apparaissent après Play
// ─────────────────────────────────────────────
const TUTO_BUBBLES = [
  { id:'btn-like', text:'Kiffez la musique de votre artiste', color:'#f04a6a', side:'left' },
  { id:'btn-comment', text:'Commentez', color:'#1a6bff', side:'right' },
  { id:'btn-kiffement', text:'Faites un kiffement à votre artiste', color:'#ffd700', side:'left' },
  { id:'btn-ziko', text:'Ajoutez à votre Zikothèque', color:'#7c3aed', side:'right' },
  { id:'btn-download', text:'Téléchargez la musique', color:'#1a6bff', side:'left' },
];

function TutoCascade({ onDone }: { onDone: () => void }) {
  const [step, setStep] = useState(0);
  const [pos, setPos] = useState<{x:number,y:number,side:string}|null>(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    if (step >= TUTO_BUBBLES.length) { onDone(); return; }
    const bubble = TUTO_BUBBLES[step];
    const el = document.getElementById(bubble.id);
    if (!el) { setStep(s => s+1); return; }
    const rect = el.getBoundingClientRect();
    setPos({ x: rect.left + rect.width/2, y: rect.top + rect.height/2, side: bubble.side });
    setVisible(true);
    const t = setTimeout(() => {
      setVisible(false);
      setTimeout(() => setStep(s => s+1), 300);
    }, 2500);
    return () => clearTimeout(t);
  }, [step]); // eslint-disable-line react-hooks/exhaustive-deps

  if (step >= TUTO_BUBBLES.length || !pos) return null;
  const bubble = TUTO_BUBBLES[step];

  return (
    <div style={{ position:'fixed', zIndex:9990, pointerEvents:'none', inset:0 }}>
      {/* Cercle pulsant sur le bouton */}
      <div style={{
        position:'absolute',
        left: pos.x - 24,
        top: pos.y - 24,
        width: 48, height: 48,
        borderRadius: 99,
        border: `2px solid ${bubble.color}`,
        boxShadow: `0 0 0 4px ${bubble.color}33`,
        opacity: visible ? 1 : 0,
        transition: 'opacity .3s',
        animation: visible ? 'tutoPulse 1s ease infinite' : 'none',
      }} />
      {/* Bulle texte */}
      <div style={{
        position:'absolute',
        left: bubble.side === 'left' ? pos.x - 180 : pos.x + 12,
        top: pos.y - 20,
        background: bubble.color,
        color: '#fff',
        fontWeight: 700,
        fontSize: 12,
        borderRadius: 10,
        padding: '8px 14px',
        maxWidth: 160,
        lineHeight: 1.4,
        opacity: visible ? 1 : 0,
        transform: visible ? 'translateY(0)' : 'translateY(8px)',
        transition: 'all .3s ease',
        boxShadow: '0 4px 16px rgba(0,0,0,0.3)',
        whiteSpace: 'pre-wrap',
      }}>
        {bubble.text}
        {/* Flèche */}
        <div style={{
          position:'absolute',
          top: '50%',
          [bubble.side === 'left' ? 'right' : 'left']: -6,
          transform: 'translateY(-50%)',
          width: 0, height: 0,
          borderTop: '6px solid transparent',
          borderBottom: '6px solid transparent',
          [bubble.side === 'left' ? 'borderLeft' : 'borderRight']: `6px solid ${bubble.color}`,
        }} />
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// FAN PAGE
// ─────────────────────────────────────────────

// ─────────────────────────────────────────────
// VIDEO PLAYER — pub avant/après comme YouTube
// ─────────────────────────────────────────────
function VideoPlayer({ files }: { files: any[] }) {
  const [idx, setIdx] = useState(0);
  const [showPubBefore, setShowPubBefore] = useState(true);
  const [showPubAfter, setShowPubAfter] = useState(false);
  const [countdown, setCountdown] = useState(10);
  const [pendingIdx, setPendingIdx] = useState<number|null>(null);
  const ref = useRef<HTMLVideoElement>(null);
  const countRef = useRef<any>(null);
  if (!files || files.length === 0) return null;
  const cur = files[idx];

  // Compte à rebours 10s avant pub vidéo
  useEffect(() => {
    if (!showPubBefore) return;
    setCountdown(10);
    countRef.current = setInterval(() => {
      setCountdown(c => {
        if (c <= 1) { clearInterval(countRef.current); return 0; }
        return c - 1;
      });
    }, 1000);
    return () => clearInterval(countRef.current);
  }, [showPubBefore, idx]);

  return (
    <div style={{ background: '#000', borderRadius: 14, overflow: 'hidden', marginBottom: 16 }}>

      {/* Compte à rebours avant pub */}
      {showPubBefore && countdown > 0 && (
        <div style={{ position:'relative' }}>
          <video ref={ref} key={cur?.url} src={cur?.url} style={{ width:'100%', maxHeight:280, display:'block', opacity:0.3 }} />
          <div style={{ position:'absolute', inset:0, display:'flex', alignItems:'center', justifyContent:'center', flexDirection:'column', gap:8 }}>
            <div style={{ width:56, height:56, borderRadius:99, border:'3px solid #fff', display:'flex', alignItems:'center', justifyContent:'center' }}>
              <span style={{ color:'#fff', fontWeight:900, fontSize:22 }}>{countdown}</span>
            </div>
            <p style={{ color:'rgba(255,255,255,0.7)', fontSize:12 }}>Publicité dans {countdown}s</p>
          </div>
        </div>
      )}

      {/* Pub avant lecture vidéo */}
      {showPubBefore && countdown === 0 && (
        <PubOverlay trigger="play" onDone={() => { setShowPubBefore(false); ref.current?.play(); }} />
      )}

      {/* Pub après fin vidéo */}
      {showPubAfter && (
        <PubOverlay trigger="track" onDone={() => {
          setShowPubAfter(false);
          if (pendingIdx !== null) {
            setIdx(pendingIdx);
            setPendingIdx(null);
            // Pas de pub avant la vidéo suivante — seulement à la fin
          }
        }} />
      )}

      {/* Lecteur vidéo */}
      {!showPubBefore && !showPubAfter && (
        <video
          ref={ref}
          key={cur?.url}
          src={cur?.url}
          controls
          controlsList="nodownload"
          style={{ width: '100%', maxHeight: 280, background: '#000', display: 'block' }}
          onEnded={() => {
            if (idx < files.length - 1) {
              setPendingIdx(idx + 1);
              setShowPubAfter(true);
            }
          }}
        />
      )}

      {/* Titre */}
      <div style={{ padding: '10px 16px', background:'rgba(0,0,0,0.8)' }}>
        <p style={{ fontWeight: 700, fontSize: 13, color:'#fff' }}>{cur?.name?.replace(/\.[^/.]+$/, '') || 'Clip ' + (idx + 1)}</p>
        <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: 11, marginTop: 2 }}>{idx + 1} / {files.length}</p>
      </div>

      {/* Liste clips */}
      {files.length > 1 && (
        <div style={{ padding: '8px 0', background:'rgba(0,0,0,0.6)' }}>
          {files.map((f, i) => (
            <div key={i} onClick={() => {
              if (i !== idx) {
                setPendingIdx(i);
                setShowPubAfter(true);
              }
            }}
              style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '8px 16px', cursor: 'pointer', background: i === idx ? 'rgba(30,111,255,0.2)' : 'transparent' }}>
              <span style={{ color: i === idx ? '#4da6ff' : 'rgba(255,255,255,0.4)', fontSize: 14 }}>{i === idx ? '▶' : '○'}</span>
              <span style={{ fontSize: 12, color: i === idx ? '#fff' : 'rgba(255,255,255,0.6)', flex: 1, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                {f.name?.replace(/\.[^/.]+$/, '') || 'Clip ' + (i + 1)}
              </span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// ─────────────────────────────────────────────
// MEDIA PLAYERS — Audio + Video séparés
// ─────────────────────────────────────────────
function MediaPlayers({ files, onStream, onSafari, downloaded, onMarkDownloaded }:
  { files: any[], onStream: (t: string, d: number) => void, onSafari: boolean, downloaded: boolean, onMarkDownloaded: () => void }) {
  const isVideo = (f: any) => /\.(mp4|mov|avi|webm|mkv|m4v)$/i.test(f.name || '');
  const audioFiles = files.filter(f => !isVideo(f));
  const videoFiles = files.filter(f => isVideo(f));
  return (
    <>
      {audioFiles.length > 0 && (
        <div style={S.card}>
          <p style={{ color: '#8098b8', fontSize: 10, marginBottom: 12, letterSpacing: 1 }}>LECTEUR AUDIO</p>
          <AudioPlayer files={audioFiles} onStream={onStream} onPlay={() => { if (!localStorage.getItem('dz_tuto_seen_v4')) setTimeout(() => setShowTutoCascade(true), 800); }} />
          {onSafari && !downloaded && (
            <div style={{ borderTop: '1px solid #dce6f7', paddingTop: 12 }}>
              <p style={{ color: '#8098b8', fontSize: 10, marginBottom: 8, letterSpacing: 1 }}>APPUYEZ LONGUEMENT POUR TELECHARGER</p>
              {audioFiles.map((f: any, i: number) => (
                <a key={i} href={f.url.replace('/upload/', '/upload/fl_attachment/')} download={f.name} target="_blank" rel="noreferrer"
                  onClick={i === 0 ? onMarkDownloaded : undefined}
                  style={{ display: 'flex', alignItems: 'center', gap: 10, background: '#f5f8ff', border: '1px solid #dce6f7', borderRadius: 10, padding: '10px 14px', marginBottom: 8, textDecoration: 'none', color: '#1a2340' }}>
                  <span>🎵</span>
                  <span style={{ flex: 1, fontSize: 12, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{f.name?.replace(/\.[^/.]+$/, '')}</span>
                  <span style={{ color: '#1a6bff' }}>⬇</span>
                </a>
              ))}
            </div>
          )}
        </div>
      )}
      {videoFiles.length > 0 && (
        <div style={S.card}>
          <p style={{ color: '#8098b8', fontSize: 10, marginBottom: 12, letterSpacing: 1 }}>🎬 STREAMING VIDÉO — ACHETEURS UNIQUEMENT</p>
          <VideoPlayer files={videoFiles} />
        </div>
      )}
    </>
  );
}

// ─────────────────────────────────────────────
// MODAL CONNEXION RAPIDE POUR ZIKOTHÈQUE
// S'affiche en overlay sur la page, sans navigation
// ─────────────────────────────────────────────
function ZikoLoginModal({ onSuccess, onClose }: { onSuccess: (uid: string) => void, onClose: () => void }) {
  const [mode, setMode] = useState<'choose' | 'email' | 'register'>('choose');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [displayName, setDisplayName] = useState('');
  const [msg, setMsg] = useState('');
  const [loading, setLoading] = useState(false);

  // Écouter la connexion en temps réel
  useEffect(() => {
    const unsub = onAuthStateChanged(auth, (u) => {
      if (u) { onSuccess(u.uid); }
    });
    return unsub;
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const loginGoogle = async () => {
    setLoading(true); setMsg('');
    try {
      const provider = new GoogleAuthProvider();
      const result = await signInWithPopup(auth, provider);
      onSuccess(result.user.uid);
    } catch (e: any) { setMsg(e.code === 'auth/popup-closed-by-user' ? 'Connexion annulée. Veuillez réessayer.' : 'Erreur Google: ' + e.message); setLoading(false); }
  };

  const loginEmail = async () => {
    setLoading(true); setMsg('');
    try {
      const result = await signInWithEmailAndPassword(auth, email, password);
      onSuccess(result.user.uid);
    } catch { setMsg('Email ou mot de passe incorrect'); setLoading(false); }
  };

  const registerEmail = async () => {
    if (!displayName) { setMsg('Entrez votre prénom'); return; }
    setLoading(true); setMsg('');
    try {
      const result = await createUserWithEmailAndPassword(auth, email, password);
      await updateProfile(result.user, { displayName });
      onSuccess(result.user.uid);
    } catch (e: any) { setMsg('Erreur: ' + e.message); setLoading(false); }
  };

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.85)', zIndex:999, display:'flex', alignItems:'flex-end', justifyContent:'center', padding:'0 0 0 0' }}
      onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}>
      <div style={{ width:'100%', maxWidth:500, background:'#0f1322', borderRadius:'20px 20px 0 0', padding:'28px 20px 40px', border:'1px solid rgba(255,255,255,0.1)' }}>

        {/* Poignée */}
        <div style={{ width:40, height:4, background:'rgba(255,255,255,0.15)', borderRadius:99, margin:'0 auto 20px' }} />

        {/* Titre */}
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:20 }}>
          <div>
            <p style={{ fontWeight:800, fontSize:18, color:'#fff', margin:0 }}>➕ Ajouter à ma Zikothèque</p>
            <p style={{ color:'#4a5878', fontSize:12, margin:'4px 0 0' }}>Connectez-vous pour sauvegarder cet album</p>
          </div>
          <button onClick={onClose} style={{ background:'rgba(255,255,255,0.08)', border:'none', borderRadius:99, width:32, height:32, color:'#8098b8', cursor:'pointer', fontSize:16, display:'flex', alignItems:'center', justifyContent:'center' }}>✕</button>
        </div>

        {mode === 'choose' && (
          <>
            {/* Google */}
            <button onClick={loginGoogle} disabled={loading}
              style={{ display:'flex', alignItems:'center', justifyContent:'center', gap:12, width:'100%', padding:'14px', borderRadius:12, border:'1px solid rgba(255,255,255,0.12)', background:'rgba(255,255,255,0.06)', color:'#fff', fontWeight:700, fontSize:15, cursor:'pointer', marginBottom:12 }}>
              <svg width="20" height="20" viewBox="0 0 24 24"><path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/><path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/><path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z"/><path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/></svg>
              Continuer avec Google
            </button>
            <button onClick={() => setMode('email')} disabled={loading}
              style={{ display:'flex', alignItems:'center', justifyContent:'center', gap:12, width:'100%', padding:'14px', borderRadius:12, border:'1px solid rgba(255,255,255,0.12)', background:'rgba(255,255,255,0.06)', color:'#fff', fontWeight:700, fontSize:15, cursor:'pointer' }}>
              ✉️ Continuer avec l'email
            </button>
          </>
        )}

        {(mode === 'email' || mode === 'register') && (
          <>
            <button onClick={() => { setMode('choose'); setMsg(''); }} style={{ background:'none', border:'none', color:'#8098b8', cursor:'pointer', marginBottom:14, fontSize:13 }}>← Retour</button>
            {mode === 'register' && (
              <>
                <input value={displayName} onChange={e => setDisplayName(e.target.value)} placeholder="Prénom ou pseudo"
                  style={{ width:'100%', background:'rgba(255,255,255,0.06)', border:'1px solid rgba(255,255,255,0.1)', borderRadius:10, padding:'12px 14px', color:'#fff', fontSize:14, outline:'none', marginBottom:10, boxSizing:'border-box' }} />
              </>
            )}
            <input value={email} onChange={e => setEmail(e.target.value)} placeholder="Email" type="email"
              style={{ width:'100%', background:'rgba(255,255,255,0.06)', border:'1px solid rgba(255,255,255,0.1)', borderRadius:10, padding:'12px 14px', color:'#fff', fontSize:14, outline:'none', marginBottom:10, boxSizing:'border-box' }} />
            <input value={password} onChange={e => setPassword(e.target.value)} placeholder="Mot de passe" type="password"
              style={{ width:'100%', background:'rgba(255,255,255,0.06)', border:'1px solid rgba(255,255,255,0.1)', borderRadius:10, padding:'12px 14px', color:'#fff', fontSize:14, outline:'none', marginBottom:14, boxSizing:'border-box' }} />
            {msg && <p style={{ color:'#f04a6a', fontSize:12, marginBottom:10 }}>{msg}</p>}
            <button onClick={mode === 'register' ? registerEmail : loginEmail} disabled={loading}
              style={{ width:'100%', padding:'14px', borderRadius:12, border:'none', background:'linear-gradient(135deg,#7c3aed,#4f46e5)', color:'#fff', fontWeight:800, fontSize:15, cursor:'pointer', marginBottom:10 }}>
              {loading ? '⏳ Chargement...' : mode === 'register' ? 'Créer mon compte' : 'Se connecter'}
            </button>
            <button onClick={() => { setMode(mode === 'email' ? 'register' : 'email'); setMsg(''); }}
              style={{ width:'100%', padding:'12px', borderRadius:12, border:'1px solid rgba(255,255,255,0.1)', background:'transparent', color:'#8098b8', cursor:'pointer', fontSize:13 }}>
              {mode === 'email' ? "Pas de compte ? S'inscrire" : 'Déjà un compte ? Se connecter'}
            </button>
          </>
        )}
      </div>
    </div>
  );
}

function FanPage() {
  const { qrId } = useParams<{ qrId: string }>();
  const [step, setStep] = useState<'loading' | 'ready' | 'zipping' | 'done'>('loading');
  const [qrData, setQrData] = useState<any>(null);
  const [dlProgress, setDlProgress] = useState(0);
  const [dlStatus, setDlStatus] = useState('');
  const [downloaded, setDownloaded] = useState(false);
  const [zikoState, setZikoState] = useState<'idle' | 'modal' | 'adding' | 'done'>('idle');
  const [showPubAfterDL, setShowPubAfterDL] = useState(false);
  const [showZikoTuto, setShowZikoTuto] = useState(false);
  const [tutoStep, setTutoStep] = useState(0);
  const [showTutoCascade, setShowTutoCascade] = useState(false);
  const [tutoSeen, setTutoSeen] = useState(false);

  // Démarrer tuto après chargement des données
  useEffect(() => {
    if (localStorage.getItem('dz_tuto_seen_v4')) return;
    let attempts = 0;
    const tryStart = () => {
      attempts++;
      const el = document.getElementById('btn-play') || document.getElementById('btn-download') || document.getElementById('btn-like');
      if (el) {
        setTutoStep(1);
      } else if (attempts < 30) {
        setTimeout(tryStart, 300);
      }
    };
    setTimeout(tryStart, 800);
  }, []); // eslint-disable-line react-hooks/exhaustive-deps
  const onSafari = isSafari() && isIOS() && !isChromeiOS();
  const qrDocId = useRef<string>('');

  useEffect(() => {
    const load = async () => {
      const q = query(collection(db, 'qrcodes'), where('qrId', '==', qrId));
      const snap = await getDocs(q);
      if (snap.empty) { setStep('ready'); return; } // QR inexistant → page vide mais pas bloquée
      const docId = snap.docs[0].id;
      qrDocId.current = docId;
      const data = { id: docId, ...snap.docs[0].data() } as any;
      setQrData(data);
      try {
        await addDoc(collection(db, 'visits'), { qrId, artist: data.artist || '', label: data.label || '', ts: new Date().toISOString() });
        await updateDoc(doc(db, 'qrcodes', docId), { visits: (data.visits || 0) + 1 });
      } catch (e) { console.error('visit', e); }
      // Plus de mode locked — toujours ready, le DL épuisé est géré dans le JSX
      setStep('ready');
    };
    load();
  }, [qrId]); // eslint-disable-line react-hooks/exhaustive-deps

  // ── Ajouter à la Zikothèque (appelé après connexion confirmée) ──
  const doAddToZiko = async (uid: string) => {
    if (!qrData) return;
    setZikoState('adding');
    try {
      const zikoData = {
        qrId: qrData.qrId || qrId,
        label: qrData.label || '',
        artist: qrData.artist || '',
        type: qrData.type || 'album',
        files: qrData.files || [],
        coverUrl: qrData.coverUrl || '',
        addedAt: new Date().toISOString(),
      };
      const existing = await getDocs(query(
        collection(db, 'zikotheque'),
        where('uid', '==', uid),
        where('qrId', '==', zikoData.qrId)
      ));
      if (existing.empty) {
        await addDoc(collection(db, 'zikotheque'), { uid, ...zikoData });
      }
      setZikoState('done');
    } catch(e) { console.error('ziko', e); setZikoState('idle'); }
  };

  // ── Clic sur "Ajouter à ma Zikothèque" ──
  const handleAddToZiko = async () => {
    const currentUser = auth.currentUser;
    if (currentUser) {
      await doAddToZiko(currentUser.uid);
    } else {
      setZikoState('modal');
    }
  };

  // ── Enregistrer un stream ──
  const recordStream = async (trackName: string, duration: number) => {
    if (!qrData || !qrDocId.current) return;
    try {
      await addDoc(collection(db, 'streams'), {
        qrId, artist: qrData.artist || '', label: qrData.label || '',
        track: trackName, duration: Math.round(duration),
        valid: true, ts: new Date().toISOString(),
      });
      await updateDoc(doc(db, 'qrcodes', qrDocId.current), { streams: (qrData.streams || 0) + 1 });
      setQrData((prev: any) => ({ ...prev, streams: (prev.streams || 0) + 1 }));
      // Déclencher tuto cascade après la première écoute
      if (!localStorage.getItem('dz_tuto_seen_v4')) {
        setTimeout(() => setShowTutoCascade(true), 500);
      }
      if (zikoState === 'idle') setShowZikoTuto(true);
    } catch (e) { console.error('stream', e); }
  };

  const markAsDownloaded = async () => {
    if (!qrData || downloaded || !qrDocId.current) return;
    setDownloaded(true);
    const newUsed = (qrData.usedScans || 0) + 1;
    try {
      await updateDoc(doc(db, 'qrcodes', qrDocId.current), {
        usedScans: newUsed, downloads: (qrData.downloads || 0) + 1,
        // On ne bloque plus jamais — le DL devient payant quand épuisé
        status: 'active',
      });
    } catch(e) { console.error('markDL', e); }
  };

  const startDownload = async () => {
    if (!qrData) return;
    const files = qrData.files || [];
    if (files.length === 0) return;

    setStep('zipping');

    // Mobile — marquer AVANT le téléchargement pour ne pas perdre le tracking
    if (isMobileDevice()) {
      // 1. Marquer immédiatement comme téléchargé
      await markAsDownloaded();
      setDlStatus('Telechargement lance !');
      // 2. Ouvrir chaque fichier dans un nouvel onglet
      for (let i = 0; i < files.length; i++) {
        setDlProgress(Math.round(((i + 1) / files.length) * 100));
        const dlUrl = files[i].url.replace('/upload/', '/upload/fl_attachment/');
        window.open(dlUrl, '_blank');
        if (i < files.length - 1) await new Promise(r => setTimeout(r, 1500));
      }
      setDlProgress(100);
      setStep('done');
      setShowPubAfterDL(true);
      if (zikoState === 'idle') setShowZikoTuto(true);
      return;
    }

    // Desktop — ZIP
    try {
      const zip = new JSZip();
      const folder = zip.folder(qrData.label || APP_NAME) as JSZip;
      for (let i = 0; i < files.length; i++) {
        setDlStatus('Preparation ' + (i + 1) + '/' + files.length);
        setDlProgress(Math.round((i / files.length) * 70));
        try {
          const r = await fetch(files[i].url.replace('/upload/', '/upload/fl_attachment/'));
          folder.file(files[i].name, await r.blob());
        } catch (e) { console.error(e); }
      }
      setDlStatus('Compression...'); setDlProgress(80);
      const zipBlob = await zip.generateAsync({ type: 'blob', compression: 'DEFLATE', compressionOptions: { level: 6 } }, (m) => setDlProgress(80 + Math.round(m.percent * 0.2)));
      setDlProgress(100);
      const url = URL.createObjectURL(zipBlob);
      const a = document.createElement('a');
      a.href = url; a.download = (qrData.label || APP_NAME).replace(/[^a-zA-Z0-9_-]/g, '_') + '.zip';
      document.body.appendChild(a); a.click(); document.body.removeChild(a);
      setTimeout(() => URL.revokeObjectURL(url), 5000);
      await markAsDownloaded();
      setDlStatus('Telechargement lance !');
      setShowPubAfterDL(true); // pub après DL desktop
      setTimeout(() => setStep('done'), 1500);
    } catch (e: any) {
      setDlStatus('Erreur: ' + e.message);
      setStep('done');
    }
  };

  return (
    <div style={{ minHeight: '100vh', background: '#0a0c14', color: '#dde4f5', fontFamily: "'DM Sans', sans-serif" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@700;900&family=DM+Sans:wght@400;600;700&display=swap');
        @keyframes spin { to { transform: rotate(360deg) } }
        @keyframes fadeUp { from { opacity:0; transform:translateY(20px) } to { opacity:1; transform:translateY(0) } }
        .fp-row:hover { background: rgba(255,255,255,0.04) !important; }
        .fp-btn-dl:active { transform: scale(0.97); }
      `}</style>

      {/* ── LOADING ── */}
      {step === 'loading' && (
        <div style={{ display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', minHeight:'100vh', gap:16 }}>
          <div style={{ width:44, height:44, border:'3px solid #1e6fff', borderTopColor:'transparent', borderRadius:99, animation:'spin .8s linear infinite' }} />
          <p style={{ color:'#4a5878', fontSize:13 }}>Chargement...</p>
        </div>
      )}

      {/* ── READY ── */}
      {step === 'ready' && qrData && (
        <div style={{ animation:'fadeUp .35s ease', paddingBottom:40 }}>

          {/* PUB après téléchargement gratuit */}
      {/* ── TUTO CASCADE — bulles après Play ── */}
      {showTutoCascade && <TutoCascade onDone={() => { setShowTutoCascade(false); localStorage.setItem('dz_tuto_seen_v4','1'); }} />}

      {showPubAfterDL && (
        <PubOverlay trigger="download" onDone={() => setShowPubAfterDL(false)} />
      )}

      {/* PUB MAISON — supprimée sur FanPage, remplacée par tuto */}

          {/* POCHETTE — grande, visible, centrée en haut */}
          <div style={{ position:'relative', width:'100%', background:'#0a0c14' }}>
            {qrData.coverUrl ? (
              <img
                src={qrData.coverUrl}
                alt={qrData.label}
                style={{ width:'100%', maxHeight:360, objectFit:'cover', display:'block' }}
              />
            ) : (
              <div style={{ width:'100%', height:260, background:'linear-gradient(135deg,#0d1535,#1a3a6e)', display:'flex', alignItems:'center', justifyContent:'center' }}>
                <img src={LOGO_B64} alt="DZ" style={{ width:100, opacity:0.35 }} />
              </div>
            )}
            {/* dégradé bas pour accrocher le texte */}
            <div style={{ position:'absolute', bottom:0, left:0, right:0, height:120, background:'linear-gradient(transparent,#0a0c14)' }} />
          </div>

          {/* TITRE + ARTISTE */}
          <div style={{ padding:'0 18px', marginTop:-16, marginBottom:20 }}>
            <h1 style={{ fontFamily:"'Playfair Display',serif", fontSize:26, fontWeight:900, color:'#fff', marginBottom:4, lineHeight:1.1 }}>{qrData.label}</h1>
            <p style={{ color:'#6a88aa', fontSize:13 }}>par <strong style={{ color:'#4da6ff' }}>{qrData.artist}</strong></p>
          </div>

          <div style={{ padding:'0 16px', maxWidth:500, margin:'0 auto' }}>

            {/* ── TÉLÉCHARGER ──
                QR privé (totalScans défini, price=0) :
                  - scans restants → DL gratuit direct
                  - scans épuisés → DL payant via Wave (AchatWidget)
                Lien public (price > 0) → AchatWidget
            ── */}
            {qrData.files?.length > 0 && (() => {
              // QR privé = a un totalScans défini ET n'est pas un lien public
              // Un lien public a un publicLinkId ou vient de /ecoute/
              const isPrivateQR = (qrData.totalScans > 0) && !qrData.publicLinkId;
              const dlsEpuises = isPrivateQR && (qrData.usedScans || 0) >= (qrData.totalScans || 0);

              if (isPrivateQR && !dlsEpuises) return (
                /* QR privé avec scans restants = téléchargement gratuit */
                <div style={{ marginBottom:20 }}>
                  <p style={{ color:'#4a5878', fontSize:10, fontWeight:700, letterSpacing:2, marginBottom:10, textTransform:'uppercase' }}>⬇ Télécharger</p>
                  {!downloaded ? (
                    onSafari ? (
                      <button onClick={() => { const f = document.createElement('iframe'); f.style.display='none'; f.src=window.location.href.replace('https://','googlechromes://'); document.body.appendChild(f); setTimeout(()=>{ document.body.removeChild(f); window.location.href='https://apps.apple.com/app/google-chrome/id535886823'; },2500); }}
                        style={{ width:'100%', padding:'15px 20px', borderRadius:14, border:'none', background:'linear-gradient(135deg,#1e6fff,#0050d0)', color:'#fff', fontWeight:700, fontSize:15, cursor:'pointer', display:'flex', alignItems:'center', gap:12, boxShadow:'0 4px 20px rgba(30,111,255,0.4)' }}>
                        <span style={{ fontSize:22, background:'rgba(255,255,255,0.15)', borderRadius:10, padding:'4px 8px' }}>🌐</span>
                        <div style={{ textAlign:'left' }}>
                          <p style={{ margin:0, fontWeight:800 }}>Ouvrir dans Chrome</p>
                          <p style={{ margin:0, fontSize:11, opacity:0.7 }}>Requis pour télécharger sur iPhone</p>
                        </div>
                      </button>
                    ) : (
                      <button id="btn-download" onClick={startDownload}
                        style={{ width:'100%', padding:'15px 20px', borderRadius:14, border:'none', background:'linear-gradient(135deg,#1e6fff,#0050d0)', color:'#fff', fontWeight:700, fontSize:15, cursor:'pointer', display:'flex', alignItems:'center', gap:12, boxShadow:'0 4px 24px rgba(30,111,255,0.45)' }}>
                        <span style={{ fontSize:22, background:'rgba(255,255,255,0.15)', borderRadius:10, padding:'4px 8px' }}>⬇</span>
                        <div style={{ textAlign:'left' }}>
                          <p style={{ margin:0, fontWeight:800 }}>{(qrData.files?.length||0)>1 ? "Télécharger l'album complet" : 'Télécharger'}</p>
                          <p style={{ margin:0, fontSize:11, opacity:0.7 }}>
                            {(qrData.totalScans||0) - (qrData.usedScans||0)} téléchargement{((qrData.totalScans||0)-(qrData.usedScans||0))>1?'s':''} gratuit{((qrData.totalScans||0)-(qrData.usedScans||0))>1?'s':''} restant{((qrData.totalScans||0)-(qrData.usedScans||0))>1?'s':''}
                          </p>
                        </div>
                      </button>
                    )
                  ) : (
                    <div style={{ display:'flex', alignItems:'center', gap:12, padding:'14px 16px', borderRadius:14, background:'rgba(30,111,255,0.1)', border:'1px solid rgba(30,111,255,0.3)' }}>
                      <span style={{ fontSize:22 }}>✅</span>
                      <div>
                        <p style={{ fontWeight:700, fontSize:14, color:'#4da6ff', margin:0 }}>Téléchargement effectué</p>
                        <p style={{ color:'#4a5878', fontSize:11, margin:'2px 0 0' }}>Streaming illimité disponible ci-dessous</p>
                      </div>
                    </div>
                  )}
                </div>
              );

              // DL épuisés ou lien public → AchatWidget (payant)
              return (
                <>
                  {dlsEpuises && (
                    <div style={{ display:'flex', alignItems:'center', gap:10, padding:'10px 14px', borderRadius:10, background:'rgba(255,200,0,0.08)', border:'1px solid rgba(255,200,0,0.2)', marginBottom:12 }}>
                      <span style={{ fontSize:16 }}>ℹ️</span>
                      <p style={{ color:'#ffd700', fontSize:12, fontWeight:600, margin:0 }}>
                        Les téléchargements gratuits de cette pochette sont épuisés. Le téléchargement est maintenant disponible via paiement.
                      </p>
                    </div>
                  )}
                  <AchatWidget
                    qrId={qrData.qrId || qrId || ''}
                    albumLabel={qrData.label || ''}
                    artistEmail={qrData.artistEmail || ''}
                    prix={qrData.price || 0}
                    files={qrData.files || []}
                  />
                </>
              );
            })()}

            {/* ── ÉCOUTER EN STREAMING ── */}
            {qrData.files?.some((f:any) => f.name?.match(/\.(mp3|wav|aac|ogg|flac|m4a)$/i)) && (
              <div style={{ marginBottom:20 }}>
                <p style={{ color:'#4a5878', fontSize:10, fontWeight:700, letterSpacing:2, marginBottom:10, textTransform:'uppercase' }}>Écouter en streaming</p>
                <AudioPlayer
                  files={qrData.files.filter((f:any) => f.name?.match(/\.(mp3|wav|aac|ogg|flac|m4a)$/i))}
                  onStream={recordStream}
                />
              </div>
            )}

            {/* ── BARRE ACTIONS HORIZONTALE — Kiff · Commenter · Kiffement · Buzz ── */}
            <ActionBar qrId={qrId || ''} artistEmail={qrData?.artistEmail} buzz={(qrData?.visits||0)+(qrData?.streams||0)} tutoStep={tutoStep} onTutoNext={() => setTutoStep(s => s+1)} />

            {/* ── TRAVAILLEURS — classement donateurs ── */}
            {qrId && <Travailleurs qrId={qrId} artistEmail={qrData?.artistEmail} />}

            {/* ── VIDÉOS ── */}
            {qrData.files?.some((f:any) => f.name?.match(/\.(mp4|mov|avi|mkv|webm)$/i)) && (
              <div style={{ marginBottom:20 }}>
                <p style={{ color:'#4a5878', fontSize:10, fontWeight:700, letterSpacing:2, marginBottom:10, textTransform:'uppercase' }}>Vidéos</p>
                <VideoPlayer files={qrData.files.filter((f:any) => f.name?.match(/\.(mp4|mov|avi|mkv|webm)$/i))} />
              </div>
            )}

            {/* ── LISTE TITRES ── */}
            {qrData.files?.length > 0 && (
              <div style={{ marginBottom:20 }}>
                <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:10 }}>
                  <p style={{ color:'#4a5878', fontSize:10, fontWeight:700, letterSpacing:2, textTransform:'uppercase' }}>💿 Titres</p>
                  <span style={{ background:'rgba(30,111,255,0.15)', border:'1px solid rgba(30,111,255,0.3)', borderRadius:99, padding:'2px 10px', fontSize:11, fontWeight:700, color:'#4da6ff' }}>{qrData.files.length}</span>
                </div>
                <div style={{ background:'#0f1322', borderRadius:14, overflow:'hidden', border:'1px solid rgba(255,255,255,0.06)' }}>
                  {qrData.files.map((f:any, i:number) => (
                    <div key={i} className="fp-row" style={{ display:'flex', alignItems:'center', gap:12, padding:'12px 16px', borderBottom: i<qrData.files.length-1?'1px solid rgba(255,255,255,0.04)':'none', transition:'background .15s' }}>
                      <div style={{ width:34, height:34, borderRadius:8, background:'linear-gradient(135deg,#0d1535,#1a3a6e)', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0, fontSize:15 }}>
                        {f.name?.match(/\.(mp4|mov|avi|mkv)$/i)?'🎬':'🎵'}
                      </div>
                      <div style={{ flex:1, overflow:'hidden' }}>
                        <p style={{ fontSize:13, fontWeight:600, color:'#dde4f5', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap', margin:0 }}>{f.name?.replace(/\.[^/.]+$/,'')||'Piste '+(i+1)}</p>
                        <p style={{ color:'#4a5878', fontSize:10, margin:'2px 0 0' }}>{formatSize(f.size||0)}</p>
                      </div>
                      <a href={f.url.replace('/upload/','/upload/fl_attachment/')} download={f.name} target="_blank" rel="noreferrer"
                        style={{ color:'rgba(30,111,255,0.7)', fontSize:18, textDecoration:'none', padding:'4px 6px' }}>⬇</a>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* ── TUTO ZIKOTHÈQUE — après écoute ou téléchargement ── */}
            {showZikoTuto && zikoState === 'idle' && (
              <div style={{ animation:'fadeUp .4s ease', marginBottom:16, background:'rgba(124,58,237,0.12)', border:'1px solid rgba(124,58,237,0.3)', borderRadius:14, padding:'14px 16px', display:'flex', alignItems:'flex-start', gap:12 }}>
                <span style={{ fontSize:22, flexShrink:0 }}>💡</span>
                <div style={{ flex:1 }}>
                  <p style={{ fontWeight:700, fontSize:13, color:'#c4b5fd', margin:'0 0 4px' }}>
                    Vous voulez ajouter ce contenu à votre Zikothèque ?
                  </p>
                  <p style={{ color:'#8098b8', fontSize:12, lineHeight:1.6, margin:'0 0 10px' }}>
                    Retrouvez cette {qrData?.type === 'video' ? 'vidéo' : qrData?.type === 'album' ? 'album' : 'musique'} à tout moment, même sans le lien.
                  </p>
                  <div style={{ display:'flex', gap:8 }}>
                    <button id="btn-ziko" onClick={handleAddToZiko}
                      style={{ padding:'8px 16px', borderRadius:10, border:'none', background:'linear-gradient(135deg,#7c3aed,#4f46e5)', color:'#fff', fontWeight:700, fontSize:13, cursor:'pointer' }}>
                      Ajouter à ma Zikothèque
                    </button>
                    <button onClick={() => setShowZikoTuto(false)}
                      style={{ padding:'8px 12px', borderRadius:10, border:'1px solid rgba(255,255,255,0.1)', background:'transparent', color:'#8098b8', fontSize:13, cursor:'pointer' }}>
                      Plus tard
                    </button>
                  </div>
                </div>
              </div>
            )}

            {/* ── AJOUTER À MA ZIKOTHÈQUE — uniquement si pas encore téléchargé via QR privé ── */}
            {!downloaded && (zikoState === 'done' ? (
              <div style={{ display:'flex', alignItems:'center', gap:12, padding:'14px 16px', borderRadius:14, background:'rgba(30,200,100,0.1)', border:'1px solid rgba(30,200,100,0.3)', marginBottom:24 }}>
                <span style={{ fontSize:24 }}>✅</span>
                <div>
                  <p style={{ fontWeight:700, fontSize:14, color:'#4dff9a', margin:0 }}>Ajouté à ta Zikothèque !</p>
                  <a href="/ziko" style={{ color:'#4da6ff', fontSize:12, textDecoration:'none' }}>Voir ma Zikothèque →</a>
                </div>
              </div>
            ) : (
              <button onClick={handleAddToZiko} disabled={zikoState === 'adding'}
                style={{ width:'100%', padding:'15px 20px', borderRadius:14, border:'none', background:'linear-gradient(135deg,#7c3aed,#4f46e5)', color:'#fff', fontWeight:700, fontSize:15, cursor: zikoState === 'adding' ? 'default' : 'pointer', display:'flex', alignItems:'center', gap:12, marginBottom:24, opacity: zikoState === 'adding' ? 0.7 : 1, boxShadow:'0 4px 20px rgba(124,58,237,0.4)' }}>
                <span style={{ fontSize:22, background:'rgba(255,255,255,0.15)', borderRadius:10, padding:'4px 8px' }}>
                  {zikoState === 'adding' ? '⏳' : '➕'}
                </span>
                <div style={{ textAlign:'left' }}>
                  <p style={{ margin:0, fontWeight:800 }}>{zikoState === 'adding' ? 'Ajout en cours...' : 'Ajouter à ma Zikothèque'}</p>
                  <p style={{ margin:0, fontSize:11, opacity:0.7 }}>Retrouvez cet album à tout moment</p>
                </div>
              </button>
            ))}

            {/* MODAL CONNEXION RAPIDE */}
            {zikoState === 'modal' && (
              <ZikoLoginModal
                onSuccess={(uid) => doAddToZiko(uid)}
                onClose={() => setZikoState('idle')}
              />
            )}

            {/* FOOTER */}
            <div style={{ textAlign:'center' }}>
              <img src={LOGO_B64} alt="DZ" style={{ width:36, opacity:0.4, display:'block', margin:'0 auto 6px' }} />
              <p style={{ color:'rgba(100,140,200,0.25)', fontSize:9, letterSpacing:2 }}>LA MUSIQUE. UN SCAN. UN MONDE.</p>
            </div>
          </div>
        </div>
      )}

      {/* ── ZIPPING ── */}
      {step === 'zipping' && (
        <div style={{ display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', minHeight:'100vh', padding:24 }}>
          <div style={{ width:'100%', maxWidth:340, background:'#0f1322', border:'1px solid rgba(255,255,255,0.08)', borderRadius:20, padding:36, textAlign:'center' }}>
            <div style={{ width:52, height:52, border:'3px solid #1e6fff', borderTopColor:'transparent', borderRadius:99, margin:'0 auto 20px', animation:'spin .8s linear infinite' }} />
            <p style={{ fontWeight:700, fontSize:16, marginBottom:8, color:'#dde4f5' }}>Préparation...</p>
            <p style={{ color:'#4a5878', fontSize:13, marginBottom:20 }}>{dlStatus}</p>
            <div style={{ height:6, background:'rgba(255,255,255,0.06)', borderRadius:99, marginBottom:10 }}>
              <div style={{ height:'100%', width:dlProgress+'%', background:'linear-gradient(90deg,#1e6fff,#4da6ff)', borderRadius:99, transition:'width .3s' }} />
            </div>
            <p style={{ color:'#1e6fff', fontWeight:800, fontSize:28 }}>{dlProgress}%</p>
          </div>
        </div>
      )}

      {/* ── LOCKED ── */}
      {/* ── DONE ── */}
      {step === 'done' && (
        <div style={{ display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', minHeight:'100vh', padding:24 }}>
          <div style={{ width:'100%', maxWidth:340, background:'#0f1322', border:'1px solid rgba(255,255,255,0.08)', borderRadius:20, padding:36, textAlign:'center', animation:'fadeUp .4s ease' }}>
            <div style={{ width:68, height:68, borderRadius:99, background: dlStatus.startsWith('Erreur')?'rgba(240,74,106,0.15)':'rgba(30,111,255,0.15)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:34, margin:'0 auto 20px', border: dlStatus.startsWith('Erreur')?'1px solid rgba(240,74,106,0.3)':'1px solid rgba(30,111,255,0.3)' }}>
              {dlStatus.startsWith('Erreur')?'❌':'✅'}
            </div>
            <h2 style={{ fontFamily:"'Playfair Display',serif", fontSize:20, fontWeight:800, marginBottom:8, color:'#dde4f5' }}>
              {dlStatus.startsWith('Erreur')?'Erreur':'Téléchargement lancé !'}
            </h2>
            <p style={{ color:'#4a5878', fontSize:13, lineHeight:1.7, marginBottom:20 }}>
              {dlStatus.startsWith('Erreur')?dlStatus:"Vos fichiers s'ouvrent dans un nouvel onglet. Appuyez longuement pour enregistrer."}
            </p>
            {!dlStatus.startsWith('Erreur') && (
              <>
                <a href="/ziko" style={{ display:'flex', alignItems:'center', justifyContent:'center', gap:8, width:'100%', padding:'14px', fontSize:14, fontWeight:700, borderRadius:14, border:'none', background:'linear-gradient(135deg,#1e6fff,#0050d0)', color:'#fff', textDecoration:'none', marginBottom:10, boxSizing:'border-box' }}>
                  📚 Ma Zikothèque
                </a>
                <button onClick={() => setStep('ready')} style={{ width:'100%', padding:'12px', fontSize:13, fontWeight:700, borderRadius:14, border:'1px solid rgba(255,255,255,0.08)', background:'transparent', color:'#6a88aa', cursor:'pointer' }}>
                  Écouter en streaming
                </button>
              </>
            )}
            <p style={{ color:'#2a3a60', fontSize:10, marginTop:16 }}>DONIEL ZIK · La Musique. Un Scan. Un Monde.</p>
          </div>
        </div>
      )}

    </div>
  );
}
// ─────────────────────────────────────────────
// ADMIN PAGE
// ─────────────────────────────────────────────
// ─────────────────────────────────────────────
// ARTISTES TAB — Liste des artistes enregistrés
// ─────────────────────────────────────────────
// ─────────────────────────────────────────────
// RESPONSABLES TAB — créer comptes responsables commerciaux
// ─────────────────────────────────────────────
function ResponsablesTab() {
  const [responsables, setResponsables] = useState<any[]>([]);
  const [nom, setNom] = useState('');
  const [email, setEmail] = useState('');
  const [telephone, setTelephone] = useState('');
  const [password, setPassword] = useState('');
  const [msg, setMsg] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const unsub = onSnapshot(
      query(collection(db, 'responsables'), orderBy('createdAt', 'desc')),
      snap => setResponsables(snap.docs.map(d => ({ id: d.id, ...d.data() })))
    );
    return unsub;
  }, []);

  const creerCompte = async () => {
    if (!nom || !email || !password) { setMsg('Nom, email et mot de passe requis'); return; }
    setLoading(true); setMsg('');
    try {
      // Créer compte Firebase Auth
      await createUserWithEmailAndPassword(auth, email, password);
      // Enregistrer dans Firestore
      await addDoc(collection(db, 'responsables'), {
        nom, email: email.trim().toLowerCase(), telephone,
        status: 'actif', createdAt: new Date().toISOString(),
        commerciauxCount: 0,
      });
      setMsg('Compte créé avec succès !');
      setNom(''); setEmail(''); setTelephone(''); setPassword('');
    } catch(e: any) {
      setMsg('Erreur : ' + e.message);
    }
    setLoading(false);
  };

  return (
    <div>
      <h2 style={{ fontFamily:'serif', fontSize:20, fontWeight:800, marginBottom:20 }}>Responsables commerciaux</h2>

      {/* Formulaire création */}
      <div style={{ ...S.card, marginBottom:24 }}>
        <p style={{ fontWeight:700, fontSize:14, marginBottom:14 }}>Créer un compte responsable</p>
        <label style={S.lbl}>Nom complet *</label>
        <input style={S.inp} value={nom} onChange={e => setNom(e.target.value)} placeholder="Prénom Nom" />
        <label style={S.lbl}>Email *</label>
        <input style={S.inp} type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="email@exemple.com" />
        <label style={S.lbl}>Téléphone</label>
        <input style={S.inp} type="tel" value={telephone} onChange={e => setTelephone(e.target.value)} placeholder="+225 07 00 00 00 00" />
        <label style={S.lbl}>Mot de passe *</label>
        <input style={S.inp} type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="Minimum 6 caractères" />
        {msg && <p style={{ color: msg.includes('succès') ? '#00a040' : '#f04a6a', fontSize:12, marginBottom:10 }}>{msg}</p>}
        <button style={{ ...S.btn, width:'100%', padding:12 }} onClick={creerCompte} disabled={loading}>
          {loading ? 'Création...' : 'Créer le compte'}
        </button>
      </div>

      {/* Liste responsables */}
      {responsables.length === 0 ? (
        <p style={{ color:'#8098b8', fontSize:13 }}>Aucun responsable commercial créé.</p>
      ) : responsables.map(r => (
        <div key={r.id} style={{ ...S.card, marginBottom:12 }}>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start' }}>
            <div>
              <p style={{ fontWeight:700, fontSize:14, margin:0 }}>{r.nom}</p>
              <p style={{ color:'#8098b8', fontSize:12, margin:'2px 0' }}>{r.email}</p>
              {r.telephone && <p style={{ color:'#8098b8', fontSize:11, margin:0 }}>{r.telephone}</p>}
            </div>
            <div style={{ display:'flex', alignItems:'center', gap:8 }}>
              <span style={{ background:'#eaffea', border:'1px solid #4dff9a', borderRadius:99, padding:'3px 12px', fontSize:11, color:'#00a040', fontWeight:700 }}>
                Actif
              </span>
              <button onClick={async () => { if (window.confirm('Supprimer ce responsable ?')) await deleteDoc(doc(db, 'responsables', r.id)); }}
                style={{ ...S.btnRed, fontSize:11, padding:'4px 8px' }}>
                Supprimer
              </button>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}

// ─────────────────────────────────────────────
// COMMERCIAUX TAB — validation des demandes
// ─────────────────────────────────────────────
function CommerciauxtTab({ db }: { db: any }) {
  const [commerciaux, setCommerciaux] = useState<any[]>([]);
  const [responsableEmail, setResponsableEmail] = useState('');
  const [msg, setMsg] = useState('');

  useEffect(() => {
    const unsub = onSnapshot(
      query(collection(db, 'commerciaux'), orderBy('createdAt', 'desc')),
      snap => setCommerciaux(snap.docs.map(d => ({id:d.id,...d.data()})))
    );
    return unsub;
  }, [db]);

  const valider = async (c: any) => {
    await updateDoc(doc(db, 'commerciaux', c.id), {
      status: 'valide',
      responsableEmail: responsableEmail || '',
      validatedAt: new Date().toISOString(),
    });
    setMsg('✅ ' + c.nom + ' validé !');
  };

  const refuser = async (c: any) => {
    await updateDoc(doc(db, 'commerciaux', c.id), { status: 'refuse' });
  };

  const enAttente = commerciaux.filter(c => c.status === 'en_attente');
  const valides = commerciaux.filter(c => c.status === 'valide');

  return (
    <div>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:20, flexWrap:'wrap', gap:12 }}>
        <h2 style={{ fontFamily:'serif', fontSize:20, fontWeight:800 }}>👔 Commerciaux</h2>
        <div style={{ display:'flex', gap:8 }}>
          <span style={{ background:'#fff8e6', border:'1px solid #f0b84a', borderRadius:99, padding:'3px 12px', fontSize:12, color:'#b07a00', fontWeight:700 }}>
            {enAttente.length} en attente
          </span>
          <span style={{ background:'#eaffea', border:'1px solid #4dff9a', borderRadius:99, padding:'3px 12px', fontSize:12, color:'#00a040', fontWeight:700 }}>
            {valides.length} validés
          </span>
        </div>
      </div>

      {msg && <p style={{ color:'#1a6bff', fontSize:13, marginBottom:12 }}>{msg}</p>}

      {/* Email responsable optionnel */}
      <div style={{ ...S.card, background:'#f5f8ff', marginBottom:20 }}>
        <label style={S.lbl}>Email du responsable commercial (optionnel)</label>
        <input style={S.inp} type="email" value={responsableEmail} onChange={e => setResponsableEmail(e.target.value)}
          placeholder="responsable@email.com" />
        <p style={{ color:'#8098b8', fontSize:11 }}>Si renseigné, le commercial sera lié à ce responsable</p>
      </div>

      {/* EN ATTENTE */}
      {enAttente.length > 0 && (
        <div style={{ marginBottom:24 }}>
          <p style={{ fontWeight:700, fontSize:13, color:'#b07a00', marginBottom:12 }}>En attente de validation</p>
          {enAttente.map(c => (
            <div key={c.id} style={{ ...S.card, marginBottom:10, borderLeft:'3px solid #f0b84a' }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', flexWrap:'wrap', gap:8 }}>
                <div>
                  <p style={{ fontWeight:700, fontSize:14, margin:0 }}>{c.nom}</p>
                  <p style={{ color:'#8098b8', fontSize:12, margin:'2px 0' }}>{c.email}</p>
                  <p style={{ color:'#8098b8', fontSize:11, margin:0 }}>{c.telephone}</p>
                  <p style={{ color:'#b0c4d8', fontSize:10, marginTop:4 }}>{new Date(c.createdAt).toLocaleDateString('fr')}</p>
                </div>
                <div style={{ display:'flex', flexDirection:'column', gap:8, minWidth:200 }}>
                  <input
                    placeholder="Email responsable (optionnel)"
                    style={{ ...S.inp, fontSize:11, padding:'6px 10px' }}
                    defaultValue={responsableEmail}
                    onChange={e => setResponsableEmail(e.target.value)}
                  />
                  <div style={{ display:'flex', gap:8 }}>
                    <button onClick={() => valider(c)} style={{ ...S.btn, fontSize:12, padding:'6px 14px' }}>Valider</button>
                    <button onClick={() => refuser(c)} style={{ ...S.btnRed, fontSize:12, padding:'6px 14px' }}>Refuser</button>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* VALIDÉS */}
      {valides.length > 0 && (
        <div>
          <p style={{ fontWeight:700, fontSize:13, color:'#00a040', marginBottom:12 }}>Commerciaux validés</p>
          {valides.map(c => (
            <div key={c.id} style={{ ...S.card, marginBottom:10, borderLeft:'3px solid #4dff9a' }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', flexWrap:'wrap', gap:8 }}>
                <div>
                  <p style={{ fontWeight:700, fontSize:14, margin:0 }}>{c.nom}</p>
                  <p style={{ color:'#8098b8', fontSize:12, margin:'2px 0' }}>{c.email}</p>
                  {c.responsableEmail && <p style={{ color:'#8098b8', fontSize:11, margin:0 }}>Responsable : {c.responsableEmail}</p>}
                  <p style={{ color:'#b0c4d8', fontSize:10, margin:'2px 0 0' }}>Validé le {new Date(c.validatedAt||c.createdAt).toLocaleDateString('fr')}</p>
                </div>
                <div style={{ display:'flex', gap:8, alignItems:'center' }}>
                  <span style={{ background:'#eaffea', border:'1px solid #4dff9a', borderRadius:99, padding:'3px 12px', fontSize:11, color:'#00a040', fontWeight:700 }}>
                    ✅ Validé
                  </span>
                  <button onClick={async () => {
                    if (window.confirm(`Supprimer ${c.nom} ? Cette action est irréversible.`)) {
                      await deleteDoc(doc(db, 'commerciaux', c.id));
                    }
                  }} style={{ ...S.btnRed, fontSize:11, padding:'4px 8px' }}>Supprimer</button>
                  <button onClick={async () => {
                    await updateDoc(doc(db,'commerciaux',c.id),{ status:'suspendu' });
                  }} style={{ padding:'4px 8px', borderRadius:6, border:'1px solid #f0b84a', background:'rgba(240,184,74,0.1)', color:'#b07a00', fontSize:11, cursor:'pointer' }}>
                    Suspendre
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {commerciaux.length === 0 && (
        <div style={{ ...S.card, textAlign:'center', padding:40 }}>
          <p style={{ fontSize:36, marginBottom:10 }}>👔</p>
          <p style={{ color:'#5a7090', fontSize:14 }}>Aucune demande pour l'instant</p>
        </div>
      )}
    </div>
  );
}

function ArtistesTab({ db, qrcodes }: { db: any, qrcodes: any[] }) {
  const [artistes, setArtistes] = useState<any[]>([]);
  const [nom, setNom] = useState('');
  const [email, setEmail] = useState('');
  const [msg, setMsg] = useState('');
  const [loading, setLoading] = useState(false);
  const [search, setSearch] = useState('');

  useEffect(() => {
    const unsub = onSnapshot(
      query(collection(db, 'artists'), orderBy('name', 'asc')),
      snap => setArtistes(snap.docs.map(d => ({ id: d.id, ...d.data() })))
    );
    return unsub;
  }, [db]);

  const addArtiste = async () => {
    if (!nom.trim() || !email.trim()) { setMsg('Nom et email requis'); return; }
    setLoading(true); setMsg('');
    try {
      // Vérifier si email déjà enregistré
      const existing = await getDocs(query(collection(db, 'artists'), where('email','==', email.trim().toLowerCase())));
      if (!existing.empty) { setMsg('Cet email est déjà enregistré'); setLoading(false); return; }
      await addDoc(collection(db, 'artists'), {
        name: nom.trim(),
        email: email.trim().toLowerCase(),
        createdAt: new Date().toISOString(),
      });
      setMsg('✅ Artiste enregistré ! Il peut maintenant créer son compte sur /artiste');
      setNom(''); setEmail('');
    } catch(e:any) { setMsg('Erreur: ' + e.message); }
    setLoading(false);
  };

  const filtered = artistes.filter(a =>
    a.name?.toLowerCase().includes(search.toLowerCase()) ||
    a.email?.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:20, flexWrap:'wrap', gap:12 }}>
        <h2 style={{ fontFamily:'serif', fontSize:20, fontWeight:800 }}>🎤 Artistes enregistrés</h2>
        <span style={{ background:'#eaf1ff', border:'1px solid #c8d8ef', borderRadius:99, padding:'3px 12px', fontSize:12, color:'#1a6bff', fontWeight:700 }}>
          {artistes.length} artiste{artistes.length > 1 ? 's' : ''}
        </span>
      </div>

      {/* FORMULAIRE AJOUT */}
      <div style={{ ...S.card, marginBottom:20, background:'#f5f8ff' }}>
        <p style={{ fontWeight:700, fontSize:14, marginBottom:14, color:'#1a2340' }}>➕ Enregistrer un nouvel artiste</p>
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12, marginBottom:12 }}>
          <div>
            <label style={S.lbl}>Nom d'artiste *</label>
            <input style={S.inp} value={nom} onChange={e => setNom(e.target.value)}
              placeholder="Ex: Élite Doniel" onKeyDown={e => e.key==='Enter' && addArtiste()} />
          </div>
          <div>
            <label style={S.lbl}>Email *</label>
            <input style={{ ...S.inp, marginBottom:0 }} type="email" value={email} onChange={e => setEmail(e.target.value)}
              placeholder="artiste@email.com" onKeyDown={e => e.key==='Enter' && addArtiste()} />
          </div>
        </div>
        {msg && <p style={{ color: msg.startsWith('✅')?'#1a6bff':'#f04a6a', fontSize:12, marginBottom:10 }}>{msg}</p>}
        <button style={{ ...S.btn, padding:'10px 24px' }} onClick={addArtiste} disabled={loading}>
          {loading ? '⏳...' : '✅ Enregistrer'}
        </button>
        <p style={{ color:'#8098b8', fontSize:11, marginTop:10 }}>
          Après enregistrement, l'artiste peut aller sur <strong>/artiste</strong> et créer son compte avec cet email.
        </p>
      </div>

      {/* RECHERCHE */}
      <input style={{ ...S.inp, marginBottom:16 }} value={search} onChange={e => setSearch(e.target.value)}
        placeholder="🔍 Rechercher un artiste..." />

      {/* LISTE */}
      {filtered.length === 0 ? (
        <div style={{ ...S.card, textAlign:'center', padding:40 }}>
          <p style={{ fontSize:36, marginBottom:10 }}>🎤</p>
          <p style={{ color:'#5a7090', fontSize:14 }}>Aucun artiste enregistré</p>
        </div>
      ) : filtered.map(a => {
        // Compter les QR codes de cet artiste
        const artistQRs = qrcodes.filter(q => q.artistEmail === a.email || q.artist === a.name);
        const totalStreams = artistQRs.reduce((s:number, q:any) => s + (q.streams||0), 0);
        const totalDL = artistQRs.reduce((s:number, q:any) => s + (q.downloads||q.usedScans||0), 0);

        return (
          <div key={a.id} style={{ ...S.card, marginBottom:10 }}>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', flexWrap:'wrap', gap:8 }}>
              <div style={{ display:'flex', alignItems:'center', gap:12 }}>
                <div style={{ width:44, height:44, borderRadius:99, background:'linear-gradient(135deg,#eaf1ff,#c8d8ef)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:20, flexShrink:0 }}>
                  🎤
                </div>
                <div>
                  <p style={{ fontWeight:800, fontSize:15, marginBottom:2 }}>{a.name}</p>
                  <p style={{ color:'#8098b8', fontSize:12 }}>{a.email}</p>
                  <p style={{ color:'#b0c4d8', fontSize:10, marginTop:2 }}>
                    Enregistré le {new Date(a.createdAt).toLocaleDateString('fr')}
                    {a.uid && <span style={{ marginLeft:8, color:'#4dff9a', fontWeight:700 }}>✅ Compte créé</span>}
                  </p>
                </div>
              </div>
              <div style={{ display:'flex', gap:8, alignItems:'center' }}>
                {!a.uid && (
                  <span style={{ background:'#fff8e6', border:'1px solid #f0b84a', borderRadius:99, padding:'2px 10px', fontSize:10, color:'#b07a00', fontWeight:700 }}>
                    ⏳ En attente
                  </span>
                )}
                <button onClick={() => { if (window.confirm(`Supprimer ${a.name} ?`)) import('firebase/firestore').then(({deleteDoc:dd,doc:d})=>dd(d(db,'artists',a.id))); }}
                  style={{ ...S.btnRed, fontSize:11, padding:'4px 8px' }}>🗑️</button>
              </div>
            </div>

            {/* Stats rapides */}
            {artistQRs.length > 0 && (
              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:8, marginTop:12 }}>
                {[
                  { label:'QR codes', val:artistQRs.length, color:'#1a6bff' },
                  { label:'Streams', val:totalStreams, color:'#b07a00' },
                  { label:'Téléchargements', val:totalDL, color:'#1a6bff' },
                ].map((s,i) => (
                  <div key={i} style={{ background:'#f5f8ff', borderRadius:8, padding:'8px', textAlign:'center' }}>
                    <p style={{ fontWeight:800, fontSize:16, color:s.color, margin:0 }}>{s.val}</p>
                    <p style={{ color:'#8098b8', fontSize:9, margin:'2px 0 0' }}>{s.label}</p>
                  </div>
                ))}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

function ArtistFolder({ artist, qrcodes, activeCount, lockedCount, onEdit, onQrModal, onBulk, onToggle, onDelete }:
  { artist: string, qrcodes: any[], activeCount: number, lockedCount: number,
    onEdit: (q: any) => void, onQrModal: (q: any) => void, onBulk: (q: any) => void,
    onToggle: (q: any) => void, onDelete: (id: string) => void }) {
  const [open, setOpen] = useState(true);

  return (
    <div style={{ marginBottom: 16 }}>
      {/* EN-TÊTE DOSSIER ARTISTE */}
      <div onClick={() => setOpen(o => !o)}
        style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '14px 18px', borderRadius: open ? '12px 12px 0 0' : 12, background: '#ffffff', border: '1px solid #c8d8ef', cursor: 'pointer', userSelect: 'none' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <span style={{ fontSize: 22 }}>{open ? '📂' : '📁'}</span>
          <div>
            <p style={{ fontWeight: 800, fontSize: 15 }}>{artist}</p>
            <p style={{ color: '#8098b8', fontSize: 11, marginTop: 2 }}>
              {qrcodes.length} QR code{qrcodes.length > 1 ? 's' : ''} · 
              <span style={{ color: '#1a6bff' }}>{activeCount} actif{activeCount > 1 ? 's' : ''}</span>
              {lockedCount > 0 && <span style={{ color: '#b07a00' }}> · {lockedCount} bloqué{lockedCount > 1 ? 's' : ''}</span>}
            </p>
          </div>
        </div>
        <span style={{ color: '#8098b8', fontSize: 18 }}>{open ? '▲' : '▼'}</span>
      </div>

      {/* LISTE QR CODES DU DOSSIER */}
      {open && (
        <div style={{ border: '1px solid #c8d8ef', borderTop: 'none', borderRadius: '0 0 12px 12px', overflow: 'hidden' }}>
          {qrcodes.map((q, i) => {
            const isLocked = q.status === 'locked' || (q.usedScans || 0) >= (q.totalScans || 1);
            return (
              <div key={q.id} style={{ padding: '16px 18px', borderTop: i === 0 ? 'none' : '1px solid #dce6f7', background: isLocked ? '#fffdf5' : '#fafcff' }}>
                <div style={{ display: 'flex', gap: 14, flexWrap: 'wrap', alignItems: 'flex-start' }}>
                  {/* QR CODE IMAGE */}
                  <div style={{ background: 'white', padding: 7, borderRadius: 8, flexShrink: 0, cursor: 'pointer' }} onClick={() => onQrModal(q)}>
                    <QRCodeSVG value={q.url} size={68} bgColor="#ffffff" fgColor="#060a14" />
                    <p style={{ color: '#060a14', fontSize: 8, textAlign: 'center', marginTop: 2, fontWeight: 700 }}>{q.qrId}</p>
                  </div>
                  {/* INFOS */}
                  <div style={{ flex: 1, minWidth: 140 }}>
                    <div style={{ display: 'flex', gap: 8, alignItems: 'center', marginBottom: 4, flexWrap: 'wrap' }}>
                      <span style={{ fontWeight: 800, fontSize: 14 }}>{q.label}</span>
                      <span style={badgeStyle(isLocked ? 'locked' : 'active')}>{isLocked ? 'Bloqué' : 'Actif'}</span>
                      <span style={{ fontFamily: 'monospace', color: '#1a6bff', fontSize: 11, fontWeight: 700 }}>{q.qrId}</span>
                    </div>
                    <p style={{ color: '#5a7090', fontSize: 12, marginBottom: 4 }}>{q.type} · {(q.price || 0).toLocaleString()} FCFA</p>
                    <p style={{ color: '#8098b8', fontSize: 11, marginBottom: 6 }}>
                      {q.fileCount || 0} fichier(s) · {q.usedScans || 0}/{q.totalScans || 0} scans · {(q.downloads !== undefined ? q.downloads : (q.usedScans || 0))} DL · {q.visits || 0} visites · {q.streams || 0} streams
                    </p>
                    <div style={{ height: 3, background: '#dce6f7', borderRadius: 99, marginBottom: 4 }}>
                      <div style={{ height: '100%', width: Math.min(100, Math.round(((q.usedScans || 0) / (q.totalScans || 1)) * 100)) + '%', background: isLocked ? '#f04a6a' : '#1a6bff', borderRadius: 99 }} />
                    </div>
                    <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', marginTop: 6 }}>
                      {q.streams > 0 && <span style={{ fontSize: 10, padding: '2px 7px', borderRadius: 6, background: '#f5f8ff', color: '#b07a00' }}>🎵 {q.streams} streams</span>}
                      {q.validStreams > 0 && <span style={{ fontSize: 10, padding: '2px 7px', borderRadius: 6, background: '#eaf1ff', color: '#1a6bff' }}>✅ {q.validStreams} validés</span>}
                    </div>
                  </div>
                  {/* ACTIONS */}
                  <div style={{ display: 'flex', flexDirection: 'column', gap: 6, flexShrink: 0 }}>
                    <button style={{ ...S.btn, padding: '6px 10px', fontSize: 11 }} onClick={() => onQrModal(q)}>QR PNG</button>
                    <button style={{ background: '#1a1a2e', border: '1px solid #4a4af0', color: '#a0a0ff', borderRadius: 8, padding: '6px 10px', fontSize: 11, cursor: 'pointer', fontWeight: 700 }} onClick={() => onBulk(q)}>🖨️ Masse</button>
                    <button style={{ ...S.btn2, fontSize: 11 }} onClick={() => onEdit(q)}>{isLocked ? '🔓 Réactiver' : '✏️ Modifier'}</button>
                    <button style={isLocked ? { ...S.btn2, color: '#1a6bff', borderColor: '#4da6ff', fontSize: 11 } : { ...S.btn2, color: '#b07a00', borderColor: '#f0b84a', fontSize: 11 }}
                      onClick={() => onToggle(q)}>
                      {isLocked ? '🔓 Activer' : '🔒 Bloquer'}
                    </button>
                    <button style={{ ...S.btnRed, fontSize: 11 }} onClick={() => onDelete(q.id)}>🗑️</button>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
// ─────────────────────────────────────────────
// HOOK — charger une pub active aléatoire
// ─────────────────────────────────────────────
function useActivePub() {
  const [pub, setPub] = useState<any>(null);
  useEffect(() => {
    getDocs(query(collection(db, 'pubs'), where('active','==',true)))
      .then(snap => {
        if (snap.empty) return;
        const list = snap.docs.map(d => ({id:d.id,...d.data()}));
        setPub(list[Math.floor(Math.random()*list.length)]);
      }).catch(()=>{});
  }, []);
  return pub;
}

// ─────────────────────────────────────────────
// PUB OVERLAY — 2 pubs en séquence
// Règle Doniel Zik : bouton Passer après 8s toujours
// Durée pub : 30s — si pas de clic Passer, pub suivante automatique
// ─────────────────────────────────────────────
function PubOverlay({ trigger, onDone, silent }: { trigger: 'page'|'play'|'download'|'track'|'audio_during', onDone: () => void, silent?: boolean }) {
  const [pubs, setPubs] = useState<any[]>([]);
  const [pubIndex, setPubIndex] = useState(0);
  const [elapsed, setElapsed] = useState(0); // secondes écoulées sur la pub courante
  const [dismissed, setDismissed] = useState(false);

  const PUB_DURATION = 30; // durée totale par pub
  const SKIP_AFTER = 5;    // bouton Passer disponible après 5s — règle Doniel Zik

  // Charger 2 pubs actives
  useEffect(() => {
    getDocs(query(collection(db, 'pubs'), where('active','==',true)))
      .then(snap => {
        if (snap.empty) { onDone(); return; }
        const list = snap.docs.map(d => ({id:d.id,...d.data()}));
        const shuffled = list.sort(() => Math.random() - 0.5);
        setPubs(shuffled.slice(0, 2));
      }).catch(() => onDone());
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const pub = pubs[pubIndex];

  // Compter la vue
  useEffect(() => {
    if (!pub) return;
    updateDoc(doc(db,'pubs',pub.id),{vues:(pub.vues||0)+1}).catch(()=>{});
    setElapsed(0); // reset chrono à chaque nouvelle pub
  }, [pub?.id]); // eslint-disable-line react-hooks/exhaustive-deps

  // Chrono — 1 tick par seconde
  useEffect(() => {
    if (!pub || dismissed) return;
    if (elapsed >= PUB_DURATION) {
      // Pub terminée — passer à la suivante ou finir
      if (pubIndex < pubs.length - 1) {
        setPubIndex(i => i + 1);
      } else {
        onDone();
      }
      return;
    }
    const t = setTimeout(() => setElapsed(e => e + 1), 1000);
    return () => clearTimeout(t);
  }, [elapsed, pub, dismissed]); // eslint-disable-line react-hooks/exhaustive-deps

  const handleClick = async () => {
    if (!pub) return;
    try { await updateDoc(doc(db,'pubs',pub.id),{clics:(pub.clics||0)+1}); } catch(e){}
    if (pub.lienType==='tel') window.location.href=`tel:${pub.lien}`;
    else if (pub.lienType==='whatsapp') window.open(`https://wa.me/${pub.lien.replace(/\D/g,'')}`, '_blank');
    else window.open(pub.lien, '_blank');
  };

  const handleSkip = () => {
    if (elapsed < SKIP_AFTER) return;
    if (pubIndex < pubs.length - 1) {
      setPubIndex(i => i + 1);
    } else {
      setDismissed(true);
      onDone();
    }
  };

  if (!pub || dismissed) return null;

  const canSkip = elapsed >= SKIP_AFTER;
  const isLastPub = pubIndex === pubs.length - 1;
  const remaining = PUB_DURATION - elapsed;

  return (
    <div style={{ position:'fixed', inset:0, zIndex:9999, background:'rgba(0,0,0,0.92)', display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', padding:'0 16px' }}>
      <style>{`@keyframes pubIn{from{opacity:0;transform:scale(0.97)}to{opacity:1;transform:scale(1)}}`}</style>

      {/* Indicateur 1/2 · 2/2 */}
      {pubs.length > 1 && (
        <div style={{ display:'flex', gap:6, marginBottom:12, width:'100%', maxWidth:500 }}>
          {pubs.map((_,i) => (
            <div key={i} style={{ flex:1, height:3, borderRadius:99, background: i < pubIndex ? '#fff' : i === pubIndex ? 'rgba(255,255,255,0.4)' : 'rgba(255,255,255,0.2)', position:'relative', overflow:'hidden' }}>
              {i === pubIndex && (
                <div style={{ position:'absolute', left:0, top:0, height:'100%', background:'#fff', width: (elapsed/PUB_DURATION*100)+'%', transition:'width 1s linear' }} />
              )}
            </div>
          ))}
        </div>
      )}

      {/* Pub cliquable */}
      <div key={pubIndex} style={{ width:'100%', maxWidth:500, animation:'pubIn .3s ease', cursor:'pointer', position:'relative' }}
        onClick={handleClick}>
      {pub.imageUrl ? (
          pub.mediaType === 'video' ? (
            <video
              src={pub.imageUrl}
              autoPlay
              muted={silent || false}
              playsInline
              style={{ width:'100%', height:'75vh', display:'block', borderRadius:12, background:'#000', objectFit:'contain' }}
              onEnded={() => {
                if (pubIndex < pubs.length - 1) setPubIndex(i => i + 1);
                else onDone();
              }}
            />
          ) : (
            <img src={pub.imageUrl} alt={pub.titre||'Pub'} style={{ width:'100%', height:'75vh', objectFit:'contain', display:'block', borderRadius:12, background:'#000' }}
              onContextMenu={e => e.preventDefault()}
              draggable={false} />
          )
        ) : (
          <div style={{ width:'100%', height:240, borderRadius:12, background:'linear-gradient(135deg,#0d1535,#1a3a6e)', display:'flex', alignItems:'center', justifyContent:'center' }}>
            <p style={{ color:'rgba(255,255,255,0.3)', fontSize:14 }}>Publicité</p>
          </div>
        )}

        {/* Overlay texte */}
        {(pub.titre||pub.sousTitre) && (
          <div style={{ position:'absolute', bottom:0, left:0, right:0, background:'linear-gradient(transparent,rgba(0,0,0,0.85))', padding:'32px 16px 14px', borderRadius:'0 0 12px 12px' }}>
            {pub.titre && <p style={{ color:'#fff', fontWeight:700, fontSize:15, margin:'0 0 3px' }}>{pub.titre}</p>}
            {pub.sousTitre && <p style={{ color:'rgba(255,255,255,0.7)', fontSize:12, margin:0 }}>{pub.sousTitre}</p>}
          </div>
        )}

        {/* Badge PUB */}
        <div style={{ position:'absolute', top:10, left:12, background:'transparent', border:'1px solid rgba(255,255,255,0.4)', borderRadius:4, padding:'2px 8px', display:'flex', gap:6, alignItems:'center' }}>
          <span style={{ color:'rgba(255,255,255,0.8)', fontSize:9, fontWeight:700, letterSpacing:1 }}>PUB</span>
          {pubs.length > 1 && <span style={{ color:'rgba(255,255,255,0.5)', fontSize:9 }}>{pubIndex+1}/{pubs.length}</span>}
        </div>

        {/* Bouton action */}
        {pub.lien && (
          <div style={{ position:'absolute', bottom:14, right:12 }}>
            <span style={{ background:'rgba(255,255,255,0.15)', border:'1px solid rgba(255,255,255,0.3)', borderRadius:8, padding:'5px 12px', color:'#fff', fontSize:12, fontWeight:700 }}>
              {pub.lienType==='tel'?'Appeler':pub.lienType==='whatsapp'?'WhatsApp':'Voir'}
            </span>
          </div>
        )}
      </div>

      {/* Grand bouton d'action — apparaît à la fin des 30 secondes */}
      {elapsed >= PUB_DURATION && pub.lien && (
        <div style={{ width:'100%', maxWidth:500, marginTop:12 }}>
          <button onClick={handleClick}
            style={{ width:'100%', padding:'18px', borderRadius:14, border:'none', background:'linear-gradient(135deg,#1a6bff,#0050d0)', color:'#fff', fontWeight:800, fontSize:17, cursor:'pointer', letterSpacing:0.5, boxShadow:'0 4px 20px rgba(30,111,255,0.5)', animation:'pubIn .4s ease' }}>
            {pub.btnLabel || (pub.lienType==='tel' ? 'Appeler maintenant' : pub.lienType==='whatsapp' ? 'Discuter maintenant' : 'Plus d\'infos')}
          </button>
        </div>
      )}

      {/* Bouton Passer / compteur */}
      <div style={{ marginTop:14, display:'flex', alignItems:'center', justifyContent:'space-between', width:'100%', maxWidth:500 }}>
        <span style={{ color:'rgba(255,255,255,0.35)', fontSize:11 }}>{remaining}s</span>
        {!canSkip ? (
          <div style={{ background:'rgba(255,255,255,0.08)', borderRadius:8, padding:'7px 16px' }}>
            <span style={{ color:'rgba(255,255,255,0.4)', fontSize:12 }}>Passer dans {SKIP_AFTER - elapsed}s</span>
          </div>
        ) : (
          <button onClick={handleSkip}
            style={{ background:'rgba(255,255,255,0.12)', border:'1px solid rgba(255,255,255,0.25)', borderRadius:8, padding:'8px 18px', color:'#fff', fontSize:13, fontWeight:700, cursor:'pointer' }}>
            {isLastPub ? 'Ignorer et continuer' : 'Passer ›'}
          </button>
        )}
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// PUB BANNER — ouverture page + page inactive
// ─────────────────────────────────────────────
function PubBanner() {
  const [shown, setShown] = useState(false);
  const [done, setDone] = useState(false);
  const [showInactive, setShowInactive] = useState(false);
  const [inactiveDone, setInactiveDone] = useState(false);
  const inactiveTimer = useRef<any>(null);
  // Délai aléatoire entre 45 et 60 secondes
  const getInactiveDelay = () => (45 + Math.random() * 15) * 1000;

  // Pub d'ouverture de page
  useEffect(() => {
    const t = setTimeout(() => setShown(true), 800);
    return () => clearTimeout(t);
  }, []);

  // Pub page inactive — se déclenche après 5 min sans activité
  const resetInactiveTimer = () => {
    if (inactiveTimer.current) clearTimeout(inactiveTimer.current);
    inactiveTimer.current = setTimeout(() => {
      setInactiveDone(false);
      setShowInactive(true);
    }, getInactiveDelay());
  };

  useEffect(() => {
    // Écouter les événements d'activité
    const events = ['mousemove', 'keydown', 'touchstart', 'scroll', 'click'];
    events.forEach(e => window.addEventListener(e, resetInactiveTimer));
    resetInactiveTimer(); // démarrer le timer dès le montage
    return () => {
      events.forEach(e => window.removeEventListener(e, resetInactiveTimer));
      if (inactiveTimer.current) clearTimeout(inactiveTimer.current);
    };
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  return (
    <>
      {/* Pub ouverture page */}
      {shown && !done && <PubOverlay trigger="page" onDone={() => setDone(true)} />}
      {/* Pub page inactive */}
      {showInactive && !inactiveDone && (
        <PubOverlay trigger="page" onDone={() => {
          setInactiveDone(true);
          setShowInactive(false);
          resetInactiveTimer(); // relancer le timer après la pub
        }} />
      )}
    </>
  );
}


