function PWAInstallBanner() {
  const [show, setShow] = useState(false);
  const [installed, setInstalled] = useState(false);

  useEffect(() => {
    if (window.matchMedia('(display-mode: standalone)').matches) { setInstalled(true); return; }
    const onAvailable = () => {
      const dismissed = localStorage.getItem('pwa-dismissed');
      const dismissedAt = dismissed ? parseInt(dismissed) : 0;
      if (Date.now() - dismissedAt > 24 * 60 * 60 * 1000) setTimeout(() => setShow(true), 2000);
    };
    window.addEventListener('pwaInstallAvailable', onAvailable);
    if ((window as any).installPWA) onAvailable();
    return () => window.removeEventListener('pwaInstallAvailable', onAvailable);
  }, []);

  const handleInstall = async () => {
    if ((window as any).installPWA) { await (window as any).installPWA(); setShow(false); setInstalled(true); }
  };
  const handleDismiss = () => { localStorage.setItem('pwa-dismissed', Date.now().toString()); setShow(false); };

  if (!show || installed) return null;
  return (
    <>
      <style>{`@keyframes slideUp{from{transform:translateY(100%);opacity:0}to{transform:translateY(0);opacity:1}}`}</style>
      <div style={{ position: 'fixed', bottom: 0, left: 0, right: 0, zIndex: 9999, background: '#ffffff', borderTop: '2px solid #1a6bff', boxShadow: '0 -4px 24px rgba(26,107,255,0.15)', padding: '14px 20px', animation: 'slideUp 0.4s ease', display: 'flex', alignItems: 'center', gap: 14 }}>
        <img src="/icon-192x192.png" alt="DZ" style={{ width: 44, height: 44, objectFit: 'contain', borderRadius: 10, flexShrink: 0 }} />
        <div style={{ flex: 1 }}>
          <p style={{ fontWeight: 800, fontSize: 14, color: '#1a2340', marginBottom: 2 }}>Installer Doniel Zik</p>
          <p style={{ color: '#8098b8', fontSize: 12 }}>Accès rapide · Fonctionne hors-ligne</p>
        </div>
        <div style={{ display: 'flex', gap: 8, flexShrink: 0 }}>
          <button onClick={handleDismiss} style={{ padding: '8px 12px', borderRadius: 8, border: '1px solid #dce6f7', background: 'transparent', color: '#8098b8', fontSize: 12, cursor: 'pointer', fontWeight: 600 }}>Plus tard</button>
          <button onClick={handleInstall} style={{ padding: '8px 16px', borderRadius: 8, border: 'none', background: '#1a6bff', color: '#ffffff', fontSize: 13, fontWeight: 700, cursor: 'pointer' }}>⬇ Installer</button>
        </div>
      </div>
    </>
  );
}


// ─────────────────────────────────────────────
// TÉLÉCHARGER WIDGET — paiement Wave automatique
// Flux : clic → session Wave créée côté serveur → redirection Wave → webhook → DL actif
// ─────────────────────────────────────────────
function AchatWidget({ qrId, albumLabel, artistEmail, prix, files }: {
  qrId: string; albumLabel: string; artistEmail: string; prix: number; files: any[];
}) {
  const [state, setState] = useState<'idle'|'loading'|'done'|'error'>('idle');
  const [errMsg, setErrMsg] = useState('');
  const [dlActive, setDlActive] = useState(false);
  const [venteId, setVenteId] = useState('');

  const [showPubAfterPay, setShowPubAfterPay] = useState(false);

  // Écouter en temps réel si le paiement a été confirmé (via webhook Wave)
  useEffect(() => {
    if (!venteId) return;
    const unsub = onSnapshot(doc(db, 'ventes', venteId), (d) => {
      if (d.exists() && d.data()?.dlActive) {
        setDlActive(true);
        setShowPubAfterPay(true); // pub après paiement confirmé
      }
    });
    return unsub;
  }, [venteId]);

  const handlePay = async () => {
    if (state === 'loading') return;
    setState('loading');
    setErrMsg('');
    try {
      // 1. Créer la demande dans Firestore
      const artSnap = await getDocs(query(collection(db, 'artists'), where('email','==',artistEmail)));
      const artistId = artSnap.empty ? '' : (artSnap.docs[0].data().uid || artSnap.docs[0].id);
      const venteRef = await addDoc(collection(db, 'ventes'), {
        qrId, artistId, artistEmail, albumLabel, prix,
        statut: 'en_attente', dlActive: false,
        readByArtist: false, createdAt: new Date().toISOString(),
      });
      setVenteId(venteRef.id);

      // 2. Appeler la Vercel Serverless Function pour créer la session Wave
      const res = await fetch('/api/wave-checkout', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          amount: prix,
          albumLabel,
          qrId,
          venteId: venteRef.id,
          type: 'album',
        }),
      });

      if (!res.ok) {
        const err = await res.json();
        throw new Error(err.error || 'Erreur serveur');
      }

      const { wave_launch_url } = await res.json();

      // 3. Rediriger vers Wave pour le paiement
      // Wave redirigera vers /fan/:qrId?payment=success après paiement
      window.location.href = wave_launch_url;

    } catch (e: any) {
      if (e.message?.includes('permissions')) {
        setErrMsg('Connexion Firestore refusée. Vérifiez les règles de sécurité.');
      } else if (e.message?.includes('wave-checkout') || e.message?.includes('fetch')) {
        setErrMsg('Service de paiement non disponible. Réessayez plus tard.');
      } else {
        setErrMsg(e.message || 'Erreur lors de la création du paiement');
      }
      setState('error');
    }
  };

  const downloadAll = () => {
    files.forEach((f:any, i:number) => {
      setTimeout(() => {
        const a = document.createElement('a');
        a.href = f.url.replace('/upload/','/upload/fl_attachment/');
        a.download = f.name; a.target = '_blank';
        document.body.appendChild(a); a.click(); document.body.removeChild(a);
      }, i * 1200);
    });
  };

  // Téléchargement activé (après confirmation Wave webhook)
  if (dlActive) return (
    <div style={{ marginBottom:20 }}>
      {/* Pub après paiement confirmé */}
      {showPubAfterPay && (
        <PubOverlay trigger="download" onDone={() => setShowPubAfterPay(false)} />
      )}
      <p style={{ color:'#4a5878', fontSize:10, fontWeight:700, letterSpacing:2, marginBottom:10, textTransform:'uppercase' }}>⬇ Télécharger</p>
      <div style={{ background:'rgba(77,255,154,0.1)', border:'1px solid rgba(77,255,154,0.35)', borderRadius:14, padding:'16px 18px', marginBottom:12 }}>
        <p style={{ fontWeight:800, fontSize:15, color:'#4dff9a', margin:'0 0 4px' }}>✅ Paiement confirmé !</p>
        <p style={{ color:'#6a88aa', fontSize:12, margin:'0 0 14px' }}>Wave a confirmé votre paiement. Votre téléchargement est prêt.</p>
        <button onClick={downloadAll}
          style={{ width:'100%', padding:'15px', borderRadius:12, border:'none', background:'linear-gradient(135deg,#4dff9a,#00c060)', color:'#000', fontWeight:800, fontSize:16, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', gap:10 }}>
          <span style={{ fontSize:22 }}>⬇</span> Télécharger maintenant
        </button>
      </div>
    </div>
  );

  return (
    <div style={{ marginBottom:20 }}>
      <p style={{ color:'#4a5878', fontSize:10, fontWeight:700, letterSpacing:2, marginBottom:10, textTransform:'uppercase' }}>⬇ Télécharger</p>
      {state === 'error' && (
        <div style={{ background:'rgba(240,74,106,0.1)', border:'1px solid rgba(240,74,106,0.3)', borderRadius:10, padding:'10px 14px', marginBottom:12 }}>
          <p style={{ color:'#f04a6a', fontSize:12, margin:0 }}>⚠ {errMsg}</p>
        </div>
      )}
      <button onClick={handlePay} disabled={state === 'loading'}
        style={{ width:'100%', padding:'15px 20px', borderRadius:14, border:'none', background: state === 'loading' ? 'rgba(30,111,255,0.5)' : 'linear-gradient(135deg,#1e6fff,#0050d0)', color:'#fff', fontWeight:700, fontSize:15, cursor: state === 'loading' ? 'default' : 'pointer', display:'flex', alignItems:'center', gap:12, boxShadow:'0 4px 20px rgba(30,111,255,0.4)' }}>
        <span style={{ fontSize:22, background:'rgba(255,255,255,0.15)', borderRadius:10, padding:'4px 8px', flexShrink:0 }}>
          {state === 'loading' ? '⏳' : '⬇'}
        </span>
        <div style={{ textAlign:'left' }}>
          <p style={{ margin:0, fontWeight:800 }}>
            {state === 'loading' ? 'Préparation du paiement...' : (files.length > 1 ? "Télécharger l'album" : 'Télécharger')}
          </p>
          <p style={{ margin:0, fontSize:11, opacity:0.7 }}>
            {prix > 0 ? `${prix.toLocaleString()} FCFA · Paiement sécurisé Wave` : 'Paiement Wave'}
          </p>
        </div>
      </button>
      <p style={{ color:'#2a3a60', fontSize:10, textAlign:'center', marginTop:8 }}>
        🔒 Paiement sécurisé via Wave · Téléchargement automatique après confirmation
      </p>
    </div>
  );
}

// ─────────────────────────────────────────────
// PAGE STREAMING PUBLIC — /ecoute/:publicLinkId
// ─────────────────────────────────────────────
function PublicStreamPage() {
  const { publicLinkId } = useParams<{ publicLinkId: string }>();
  const [data, setData] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [zikoState, setZikoState] = useState<'idle' | 'modal' | 'adding' | 'done'>('idle');
  const [showTutoCascade, setShowTutoCascade] = useState(false);

  // Déclencher tuto cascade après play
  // (déclenché depuis recordPublicStream)

  const recordPublicStream = async (track: string, duration: number) => {
    if (!data) return;
    try {
      await addDoc(collection(db, 'streams'), {
        publicLinkId, artist: data.artist || '', label: data.label || '',
        track, duration: Math.round(duration), valid: true,
        source: 'publicLink', ts: new Date().toISOString(),
      });
      if (data.artistEmail) {
        const qrSnap = await getDocs(query(collection(db, 'qrcodes'), where('artistEmail', '==', data.artistEmail), where('publicLinkId', '==', publicLinkId)));
        if (!qrSnap.empty) {
          await updateDoc(doc(db, 'qrcodes', qrSnap.docs[0].id), {
            streams: (qrSnap.docs[0].data().streams || 0) + 1,
          });
        }
      }
    } catch(e) { console.error('pubStream', e); }
    // Déclencher tuto cascade après premier play
    if (!localStorage.getItem('dz_tuto_seen_v4')) {
      setTimeout(() => setShowTutoCascade(true), 800);
    }
  };

  useEffect(() => {
    const load = async () => {
      const snap = await getDocs(query(collection(db, 'publicLinks'), where('publicLinkId', '==', publicLinkId)));
      if (!snap.empty) {
        const d = { id: snap.docs[0].id, ...snap.docs[0].data() } as any;
        setData(d);
        // Compter le Buzz — incrémenter visits
        try {
          await updateDoc(doc(db, 'publicLinks', snap.docs[0].id), { visits: (d.visits || 0) + 1 });
          // Aussi dans decouvrir si publié
          const dSnap = await getDocs(query(collection(db,'decouvrir'), where('publicLinkId','==',publicLinkId)));
          if (!dSnap.empty) await updateDoc(doc(db,'decouvrir',dSnap.docs[0].id),{ buzz:(dSnap.docs[0].data().buzz||0)+1 });
        } catch(e) { console.error('buzz',e); }
      }
      setLoading(false);
    };
    load();
  }, [publicLinkId]);

  const doAddToZiko = async (uid: string) => {
    if (!data) return;
    setZikoState('adding');
    try {
      const zikoData = {
        qrId: data.publicLinkId || publicLinkId,
        label: data.label || '',
        artist: data.artist || '',
        type: data.type || 'album',
        files: data.files || [],
        coverUrl: data.coverUrl || '',
        addedAt: new Date().toISOString(),
      };
      const existing = await getDocs(query(
        collection(db, 'zikotheque'),
        where('uid', '==', uid),
        where('qrId', '==', zikoData.qrId)
      ));
      if (existing.empty) {
        await addDoc(collection(db, 'zikotheque'), { uid, ...zikoData });
      }
      setZikoState('done');
    } catch(e) { console.error('ziko', e); setZikoState('idle'); }
  };

  const handleAddToZiko = async () => {
    const currentUser = auth.currentUser;
    if (currentUser) { await doAddToZiko(currentUser.uid); }
    else { setZikoState('modal'); }
  };

  if (loading) return (
    <div style={{ minHeight: '100vh', background: '#0a0c14', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
      <div style={{ width: 44, height: 44, border: '3px solid #1e6fff', borderTopColor: 'transparent', borderRadius: 99, animation: 'spin .8s linear infinite' }} />
    </div>
  );

  if (!data) return (
    <div style={{ minHeight: '100vh', background: '#0a0c14', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#dde4f5' }}>
      <div style={{ textAlign: 'center' }}><p style={{ fontSize: 48, marginBottom: 12 }}>🎵</p><p style={{ color: '#4a5878' }}>Contenu non trouvé</p></div>
    </div>
  );

  const audioFiles = (data.files || []).filter((f: any) => f.name?.match(/\.(mp3|wav|aac|ogg|flac|m4a)$/i));
  const videoFiles = (data.files || []).filter((f: any) => f.name?.match(/\.(mp4|mov|avi|mkv|webm)$/i));

  return (
    <div style={{ minHeight: '100vh', background: '#0a0c14', color: '#dde4f5', fontFamily: "'DM Sans', sans-serif", paddingBottom: 40 }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@700;900&family=DM+Sans:wght@400;600;700&display=swap');
        @keyframes spin { to { transform: rotate(360deg) } }
        @keyframes fadeUp { from { opacity:0; transform:translateY(18px) } to { opacity:1; transform:translateY(0) } }
        .ps-row:hover { background: rgba(255,255,255,0.04) !important; }
      `}</style>

      {/* PUB MAISON */}

      {/* ── TUTO CASCADE — bulles après Play ── */}
      {showTutoCascade && <TutoCascade onDone={() => { setShowTutoCascade(false); localStorage.setItem('dz_tuto_seen_v4','1'); }} />}

      {/* ── POCHETTE — grande, visible, pleine largeur ── */}
      <div style={{ position: 'relative', width: '100%', animation: 'fadeUp .35s ease' }}>
        {data.coverUrl ? (
          <img
            src={data.coverUrl}
            alt={data.label}
            style={{ width: '100%', maxHeight: '60vh', objectFit: 'cover', display: 'block' }}
          />
        ) : (
          <div style={{ width: '100%', height: 260, background: 'linear-gradient(135deg,#0d1535,#1a3a6e)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <img src={LOGO_B64} alt="DZ" style={{ width: 100, opacity: 0.35 }} />
          </div>
        )}
        {/* dégradé bas */}
        <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, height: 120, background: 'linear-gradient(transparent, #0a0c14)' }} />
      </div>

      {/* ── TITRE + ARTISTE ── */}
      <div style={{ padding: '0 18px', marginTop: -14, marginBottom: 22 }}>
        <h1 style={{ fontFamily: "'Playfair Display',serif", fontSize: 26, fontWeight: 900, color: '#fff', marginBottom: 4, lineHeight: 1.1 }}>{data.label}</h1>
        <p style={{ color: '#6a88aa', fontSize: 13 }}>par <strong style={{ color: '#4da6ff' }}>{data.artist}</strong></p>
      </div>

      <div style={{ padding: '0 16px', maxWidth: 500, margin: '0 auto' }}>

        {/* ── ÉCOUTER EN STREAMING ── */}
        {audioFiles.length > 0 && (
          <div style={{ marginBottom: 20 }}>
            <p style={{ color: '#4a5878', fontSize: 10, fontWeight: 700, letterSpacing: 2, marginBottom: 10, textTransform: 'uppercase' }}>Écouter en streaming</p>
            <AudioPlayer files={audioFiles} onStream={recordPublicStream} onPlay={() => { if (!localStorage.getItem('dz_tuto_seen_v4')) setTimeout(() => setShowTutoCascade(true), 800); }} />
          </div>
        )}

        {/* ── BARRE ACTIONS — Kiff · Commenter · Kiffement · Buzz ── */}
        <ActionBar
          qrId={data.publicLinkId || publicLinkId || ''}
          artistEmail={data.artistEmail || ''}
          buzz={(data.visits||0)+(data.streams||0)}
          tutoStep={0}
          onTutoNext={() => {}}
        />
        {(data.price > 0 || data.files?.length > 0) && (
          <AchatWidget
            qrId={data.publicLinkId || publicLinkId || ''}
            albumLabel={data.label || ''}
            artistEmail={data.artistEmail || ''}
            prix={data.price || 0}
            files={data.files || []}
          />
        )}

        {/* ── VIDÉOS ── */}
        {videoFiles.length > 0 && (
          <div style={{ marginBottom: 20 }}>
            <p style={{ color: '#4a5878', fontSize: 10, fontWeight: 700, letterSpacing: 2, marginBottom: 10, textTransform: 'uppercase' }}>Vidéos</p>
            <VideoPlayer files={videoFiles} />
          </div>
        )}

        {/* ── LISTE TITRES ── */}
        {(data.files || []).length > 0 && (
          <div style={{ marginBottom: 20 }}>
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 10 }}>
              <p style={{ color: '#4a5878', fontSize: 10, fontWeight: 700, letterSpacing: 2, textTransform: 'uppercase' }}>💿 Titres</p>
              <span style={{ background: 'rgba(30,111,255,0.15)', border: '1px solid rgba(30,111,255,0.3)', borderRadius: 99, padding: '2px 10px', fontSize: 11, fontWeight: 700, color: '#4da6ff' }}>{data.files.length}</span>
            </div>
            <div style={{ background: '#0f1322', borderRadius: 14, overflow: 'hidden', border: '1px solid rgba(255,255,255,0.06)' }}>
              {data.files.map((f: any, i: number) => (
                <div key={i} className="ps-row" style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '12px 16px', borderBottom: i < data.files.length - 1 ? '1px solid rgba(255,255,255,0.04)' : 'none', transition: 'background .15s' }}>
                  <div style={{ width: 34, height: 34, borderRadius: 8, background: 'linear-gradient(135deg,#0d1535,#1a3a6e)', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="rgba(255,255,255,0.5)" strokeWidth="2"><path d="M9 18V5l12-2v13"/><circle cx="6" cy="18" r="3"/><circle cx="18" cy="16" r="3"/></svg>
                  </div>
                  <div style={{ flex: 1, overflow: 'hidden' }}>
                    <p style={{ fontSize: 13, fontWeight: 600, color: '#dde4f5', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', margin: 0 }}>{f.name?.replace(/\.[^/.]+$/, '') || 'Piste ' + (i + 1)}</p>
                    <p style={{ color: '#4a5878', fontSize: 10, margin: '2px 0 0' }}>{formatSize(f.size || 0)}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ── AJOUTER À MA ZIKOTHÈQUE ── */}
        {zikoState === 'done' ? (
          <div style={{ display:'flex', alignItems:'center', gap:12, padding:'14px 16px', borderRadius:14, background:'rgba(30,200,100,0.1)', border:'1px solid rgba(30,200,100,0.3)', marginBottom:24 }}>
            <span style={{ fontSize:24 }}>✅</span>
            <div>
              <p style={{ fontWeight:700, fontSize:14, color:'#4dff9a', margin:0 }}>Ajouté à ta Zikothèque !</p>
              <a href="/ziko" style={{ color:'#4da6ff', fontSize:12, textDecoration:'none' }}>Voir ma Zikothèque →</a>
            </div>
          </div>
        ) : (
          <button onClick={handleAddToZiko} disabled={zikoState === 'adding'}
            style={{ width:'100%', padding:'15px 20px', borderRadius:14, border:'none', background:'linear-gradient(135deg,#7c3aed,#4f46e5)', color:'#fff', fontWeight:700, fontSize:15, cursor: zikoState === 'adding' ? 'default' : 'pointer', display:'flex', alignItems:'center', gap:12, marginBottom:24, opacity: zikoState === 'adding' ? 0.7 : 1, boxShadow:'0 4px 20px rgba(124,58,237,0.4)' }}>
            <span style={{ fontSize:22, background:'rgba(255,255,255,0.15)', borderRadius:10, padding:'4px 8px' }}>
              {zikoState === 'adding' ? '⏳' : '➕'}
            </span>
            <div style={{ textAlign:'left' }}>
              <p style={{ margin:0, fontWeight:800 }}>{zikoState === 'adding' ? 'Ajout en cours...' : 'Ajouter à ma Zikothèque'}</p>
              <p style={{ margin:0, fontSize:11, opacity:0.7 }}>Retrouvez cet album à tout moment</p>
            </div>
          </button>
        )}

        {/* MODAL CONNEXION RAPIDE */}
        {zikoState === 'modal' && (
          <ZikoLoginModal
            onSuccess={(uid) => doAddToZiko(uid)}
            onClose={() => setZikoState('idle')}
          />
        )}

        {/* FOOTER */}
        <div style={{ textAlign: 'center' }}>
          <img src={LOGO_B64} alt="DZ" style={{ width: 36, opacity: 0.35, display: 'block', margin: '0 auto 6px' }} />
          <p style={{ color: 'rgba(100,140,200,0.2)', fontSize: 9, letterSpacing: 2 }}>LA MUSIQUE. UN SCAN. UN MONDE.</p>
        </div>
      </div>
    </div>
  );
}

export default function App() {
  const [user, setUser] = useState<any>(null);
  const [authLoading, setAuthLoading] = useState(true);

  useEffect(() => {
    const unsub = onAuthStateChanged(auth, (u) => {
      setUser(u);
      setAuthLoading(false);
    });
    return unsub;
  }, []);

  return (
    <BrowserRouter>
      <PWAInstallBanner />
      <Routes>
        <Route path="/" element={
          authLoading ? (
            <div style={{ minHeight:'100vh', background:'#161b27', display:'flex', alignItems:'center', justifyContent:'center' }}>
              <div style={{ width:48, height:48, border:'3px solid #1e6fff', borderTopColor:'transparent', borderRadius:99, animation:'spin .8s linear infinite' }} />
              <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
            </div>
          ) : user ? <ZikothequePage user={user} /> : <LandingPage />
        } />
        <Route path="/fan/:qrId" element={<FanPage />} />
        <Route path="/ecoute/:publicLinkId" element={<PublicStreamPage />} />
        <Route path="/ziko" element={
          authLoading ? (
            <div style={{ minHeight:'100vh', background:'#161b27', display:'flex', alignItems:'center', justifyContent:'center' }}>
              <div style={{ width:48, height:48, border:'3px solid #1e6fff', borderTopColor:'transparent', borderRadius:99, animation:'spin .8s linear infinite' }} />
              <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
            </div>
          ) : user ? <ZikothequePage user={user} /> : <UserAuthPage />
        } />
        <Route path="/ziko/login" element={<UserAuthPage />} />
        <Route path="/artiste" element={<ArtistPage />} />
        <Route path="/artiste/login" element={<ArtistPage />} />
        <Route path="/annonceurs" element={<AnnonceursPage />} />
        <Route path="/home" element={<HomePage />} />
        <Route path="/decouvrir" element={<DecouvrirPage />} />
        <Route path="/profil" element={<ProfilPage />} />
        <Route path="/studio" element={<DzStudioPage />} />
        <Route path="/commercial" element={<CommercialPage />} />
        <Route path="/responsable" element={<ResponsablePage />} />
        <Route path="/conditions" element={<ConditionsPage />} />
        <Route path="/admin" element={<AdminPage />} />
        <Route path="/*" element={
          authLoading ? null : user ? <ZikothequePage user={user} /> : <LandingPage />
        } />
      </Routes>
    </BrowserRouter>
  );
}
